function AuthScreen({refreshAuth,error=''}){const[email,setEmail]=useState(''),[password,setPassword]=useState(''),[busy,setBusy]=useState(false),[msg,setMsg]=useState(error),submit=async e=>{e.preventDefault();setBusy(true);setMsg('');try{const r=await fetch('/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email,password})}),t=await r.text();if(!r.ok)throw new Error(JSON.parse(t||'{}')?.error||'Login failed');await refreshAuth()}catch(err){setMsg(err?.message||'Login failed')}finally{setBusy(false)}};return <Card className="space-y-5"><div className="text-center"><img src="/grease-nomads-calligraphy.png" alt="Grease Nomads" className="mx-auto h-24 w-full max-w-md object-contain"/><p className="mt-3 text-xs uppercase tracking-[0.2em] text-orange-200">Secure Access</p><h1 className="mt-2 text-3xl font-black">Sign in to the PPI dashboard</h1><p className="mt-2 text-sm text-neutral-400">Customer report links stay public. The technician dashboard and report tools require login.</p></div><form onSubmit={submit} className="space-y-3"><input type="email" autoComplete="email" required value={email} onChange={e=>setEmail(e.target.value)} className={inp} placeholder="Email"/><input type="password" autoComplete="current-password" required value={password} onChange={e=>setPassword(e.target.value)} className={inp} placeholder="Password"/>{msg&&<p className="rounded-2xl border border-red-300/30 bg-red-600/15 p-3 text-sm text-red-100">{msg}</p>}<button type="submit" disabled={busy} className="w-full rounded-2xl bg-white px-5 py-4 font-black text-black disabled:opacity-50">{busy?'Signing in...':'Sign In'}</button></form></Card>}
