function CustomerClosingSummary({groups=[],openScope=()=>{}}){return <Card id="customer-end-summary" className="bg-neutral-950/95 border-orange-300/30"><div className="mb-5"><p className="text-xs uppercase tracking-[0.2em] text-orange-200">End Of Report Summary</p><h2 className="text-2xl font-black mt-1">Review By Section</h2><p className="mt-2 max-w-2xl text-sm text-neutral-300">A section-by-section recap of anything marked monitor or needs attention. Photos stay with the exact line item when available.</p></div><div className="grid gap-4">{groups.map(g=>{const lv=customerWorst(g.records),items=g.records.filter(r=>['red','yellow'].includes(r.level)),photos=items.reduce((n,r)=>n+r.files.length,0);return <section key={g.title} className={`rounded-3xl border p-4 ${customerTone(lv)}`}><div className="flex flex-col lg:flex-row lg:items-center lg:justify-between gap-3"><div className="flex items-start gap-3"><span className={`grid h-11 w-11 shrink-0 place-items-center rounded-2xl border ${customerTone(lv)}`}><StatusGlyph level={lv}/></span><div><h3 className="text-xl font-black">{g.title}</h3><p className="text-sm opacity-85">{items.length?`${items.length} item${items.length===1?'':'s'} to review${photos?` · ${photos} photo${photos===1?'':'s'}`:''}`:'Looks good based on the entered results.'}</p></div></div><button type="button" onClick={()=>openScope(g.title)} className="rounded-xl border border-orange-200 bg-orange-400 px-4 py-3 text-sm font-black text-black">View Section</button></div>{items.length?<div className="mt-4 overflow-hidden rounded-2xl border border-white/10 bg-black/35 divide-y divide-white/10">{items.map(r=><CustomerResultRow key={r.k} row={r} anchor={false}/>)}</div>:null}</section>})}</div></Card>}
