function batteryElectricalGroups(records){const order=['General Results','Battery Test','Visual Condition','Identification & Access','Hybrid Checks'];return order.map(label=>({label,records:records.filter(r=>batteryElectricalGroupFor(r)===label)})).filter(g=>g.records.length)}
function batteryElectricalGroupFor(r){const i=r.item;if(/Battery Test Result|Battery Health|Correct Battery Installed|Electrical Warning Lights|Further Evaluation/.test(i))return'General Results';if(/Resting Battery Voltage|Measured CCA|Rated CCA/.test(i))return'Battery Test';if(/Physical Condition|Terminals|Cable|Tie-Down|Jump Post/.test(i))return'Visual Condition';if(/Powertrain|Battery Location|Battery Type|Brand|Date|Access|Programming/.test(i))return'Identification & Access';if(/Hybrid|High Voltage|Regenerative/.test(i))return'Hybrid Checks';return'General Results'}
function electricalZones(records){const base=[{id:'battery',label:'Battery',mark:'BAT',copy:'Battery results are grouped into smaller customer-friendly sections below.'},{id:'alternator',label:'Alternator',mark:'ALT',copy:'Charging output and charging-system observations are grouped here.'},{id:'starter',label:'Starter',mark:'START',copy:'Starting measurements, start behavior, and warning-light observations are grouped here.'},{id:'scan',label:'Scan & Readiness',mark:'SCAN',copy:'All vehicle scan, code, readiness, and scan-report photo results are grouped here.'}];return base.map(z=>({...z,records:records.filter(r=>electricalZoneFor(r)===z.id)})).filter(z=>z.records.length)}
