function visualZones(type,cats){const labels=cats.map(([cat])=>cat),base={exterior:[['Front Exterior','Front','5%','37%','21%','26%'],['Right Exterior','Right Side','29%','7%','42%','18%'],['Left Exterior','Left Side','29%','75%','42%','18%'],['Rear Exterior','Rear','74%','37%','21%','26%'],['Paint and Body','Paint / Body','35%','29%','30%','13%'],['Exterior Lighting Operation','Lighting','35%','43.5%','30%','13%'],['Final Checks','Final Checks','35%','58%','30%','13%']],interior:[['Driver Seat Position','Driver Seat Area','12%','28%','28%','18%'],['Passenger Seat Position','Passenger Seat Area','60%','28%','28%','18%'],['Rear Seat Position','Rear Seat Area','22%','63%','56%','17%'],['Trunk / Cargo Area','Cargo Area','32%','84%','36%','10%'],['Interior Quick Check','Cabin Check','28%','39%','44%','18%'],['Interior Final Checks','Interior Final Checks','33%','47%','34%','13%']],underbody:[['Steering System','Steering','3%','43%','14%','12%'],['Engine Mounts','Engine Mounts','18%','28%','15%','11%'],['Strut Towers / Mounts','Strut Mounts','18%','60%','15%','11%'],['Front Suspension','Front Suspension','23%','43%','14%','12%'],['Front Underbody','Front Underbody','18%','43%','18%','13%'],['Fluids & Leaks','Lines / Leaks','43%','14%','14%','11%'],['Driveline','Driveline','43%','43%','14%','12%'],['Frame, Leaks & Exhaust','Frame / Leaks / Exhaust','40%','68%','23%','12%'],['Rear Suspension','Rear Suspension','63%','43%','14%','12%'],['Rear Underbody','Rear Underbody','64%','43%','18%','13%'],['Exhaust System','Exhaust','83%','43%','14%','12%'],['Frame & Structure','Frame','32%','74%','14%','11%'],['Fasteners & Undertray','Undertray','54%','74%','14%','11%']]}[type]||[];return base.filter(([cat])=>labels.includes(cat)).map(([cat,label,x,y,w,h])=>({cat,label,x,y,w,h}))}
