function interiorLineGroups(records,scope=''){const out=[];records.forEach(r=>{const label=interiorLineGroupLabel(r.item,scope),g=out.find(x=>x.label===label);g?g.records.push(r):out.push({label,records:[r]})});const order=['Seat & Belts','Safety','Controls & Features','Windows & Mirrors','Storage & Releases','Lighting','Trim & Condition','Air Quality & Moisture','Cargo Area','Interior Items'];return out.sort((a,b)=>{const ai=order.indexOf(a.label),bi=order.indexOf(b.label);return(ai<0?99:ai)-(bi<0?99:bi)})}
function interiorLineGroupLabel(item,scope=''){if(scope==='Interior Quick Check'){if(/Driver Seat|Seat Belt/.test(item))return'Seat & Belts';if(/Shifter|Horn|Locks|Windows/.test(item))return'Controls & Features';if(/Interior Lighting/.test(item))return'Lighting';if(/Odor|Water|Moisture|Cabin Air Filter|Pollen/.test(item))return'Air Quality & Moisture';return'Safety'}if(/Seat Belt|Child Lock|Key Fob|Horn|Panic|Lock \/ Unlock|Locks Operation|Safety/.test(item))return'Safety';if(/Driver Seat$|Passenger Seat$|Rear Seats|Seat Adjustment|Heated|Ventilated|Massaging/.test(item))return'Seat & Belts';if(/Steering Wheel Controls|Infotainment|USB|12V|HVAC|Button|Feature Operation/.test(item))return'Controls & Features';if(/Window|Mirror/.test(item))return'Windows & Mirrors';if(/Fuel Door Release|Hood Release|Trunk Release|Glovebox Operation|Center Console Operation/.test(item))return'Storage & Releases';if(/Interior Lighting|Cargo \/ Trunk Light|Sunroof|Sun Visors \/ Vanity Mirrors Operation/.test(item))return'Lighting';if(/Door Handle|Dashboard|Steering Wheel Wear|Console Condition|Glovebox Condition|Interior Trim|Visors \/ Vanity Mirrors Condition|Carpet|Headliner|Cargo Area Trim|Trunk \/ Cargo Area Condition/.test(item))return'Trim & Condition';if(/Odor|Water|Moisture|Filter/.test(item))return'Air Quality & Moisture';if(/Cargo|Trunk/.test(item))return'Cargo Area';return'Interior Items'}
function CustomerMiniResult({row}){const[open,setOpen]=useState(false),[full,setFull]=useState(null),hasPhotos=row.files.length>0,label=customerItemLabel(row.item);return <div id={`customer-row-${id(row.k)}`} className="rounded-xl border border-white/10 bg-black/30 p-3 scroll-mt-24"><div className="flex items-start gap-2"><span className={`mt-0.5 grid h-7 w-7 shrink-0 place-items-center rounded-lg border text-sm font-black ${customerTone(row.level)}`}><StatusGlyph level={row.level}/></span><div className="min-w-0 flex-1"><p className="font-bold leading-snug break-words">{label}</p><p className="mt-1 text-sm opacity-85 whitespace-pre-line leading-relaxed break-words">{row.text}</p></div></div>{hasPhotos&&<button type="button" onClick={()=>setOpen(!open)} className="mt-3 rounded-lg border border-orange-300/30 px-2 py-1 text-[11px] text-orange-100 hover:bg-orange-500/20">{open?'Hide Media':`View Media (${row.files.length})`}</button>}{open&&hasPhotos&&<div className="mt-3 grid gap-2">{row.files.map((p,i)=><figure key={i} className="rounded-xl border border-white/10 bg-black p-2"><MediaThumb media={p} label={label} onOpen={()=>setFull(p)} className="h-36 w-full"/><figcaption className="mt-1 text-[11px] opacity-70 break-words">{p.name||p.label||label}</figcaption></figure>)}</div>}<PhotoLightbox photo={full} label={label} close={()=>setFull(null)}/></div>}
function CustomerReviewCompactRow({row}){const[help,setHelp]=useState(false),label=customerItemLabel(row.item),result=reviewResultText(row),action=reviewActionText(row);return <div className={`relative rounded-2xl border p-4 pr-12 ${customerTone(row.level)}`}><div className="grid gap-3 lg:grid-cols-[1.05fr_.95fr_1fr] lg:items-start"><div><p className="text-[10px] uppercase tracking-[0.16em] opacity-75">Line Item</p><p className="mt-1 font-black leading-snug">{label}</p></div><div><p className="text-[10px] uppercase tracking-[0.16em] opacity-75">Result</p><p className="mt-1 text-sm font-bold leading-relaxed">{result}</p></div><div><p className="text-[10px] uppercase tracking-[0.16em] opacity-75">Recommended Action</p><p className="mt-1 text-sm font-bold leading-relaxed">{action}</p></div></div><button type="button" onClick={()=>setHelp(true)} aria-label={`Explain ${label}`} className="absolute bottom-3 right-3 grid h-8 w-8 place-items-center rounded-full border border-white/30 bg-black/30 text-sm font-black hover:bg-black/50">?</button>{help&&<CustomerHelpModal row={row} label={label} result={result} action={action} close={()=>setHelp(false)}/>}</div>}
function CustomerHelpModal({row,label,result,action,close}){return <div className="fixed inset-0 z-[100] grid place-items-center bg-black/85 p-4" role="dialog" aria-modal="true" onClick={close}><div className="flex max-h-[88vh] w-full max-w-2xl flex-col rounded-3xl border border-orange-300/30 bg-neutral-950 p-5 text-white shadow-2xl" onClick={e=>e.stopPropagation()}><div className="flex shrink-0 items-start justify-between gap-3 border-b border-orange-300/20 pb-4"><div><p className="text-xs uppercase tracking-[0.18em] text-orange-200">Why This Matters</p><h3 className="mt-1 text-2xl font-black">{label}</h3></div><button type="button" onClick={close} className="rounded-xl bg-white px-4 py-2 text-sm font-black text-black">Close</button></div><div className="mt-4 grid min-h-0 gap-3 overflow-y-auto overscroll-contain pr-2"><Info label="Result" value={result} level={row.level}/><Info label="Recommended Action" value={action} level={row.level}/><Info label="How It Can Affect The Vehicle" value={customerEducationText(row)} level="neutral"/></div></div></div>}
function reviewResultText(row){const v=displayValue(row.value);if(row.item.includes('Brake Pad'))return`${numOnly(row.value)} mm`;if(tireMeasurementItem(row.item)){const p=['Inner','Center','Outer'].map(x=>tireVal(row.value,x)&&`${x}: ${tireVal(row.value,x)}/32nd`).filter(Boolean).join(' / ');return p||v}return v}
function reviewActionText(row){const s=String(row.value||''),i=row.item;if(/Due Now/.test(s))return'Plan for this upcoming service.';if(/Recommended/.test(s))return'Plan this item for an upcoming service and monitor.';if(/Could Not Verify|Unable to Verify|Not Performed/.test(s))return'Recheck when access or conditions allow.';if(row.level==='red'){if(/Tire Condition/.test(i)&&s.includes('Sidewall Damage'))return'Tire replacement should be planned.';if(i.includes('Brake Pad'))return'Brake service should be planned.';if(/Air Filter|Cabin Air Filter|Pollen/.test(i))return'Filter replacement should be planned.';if(/Engine Oil/.test(i)&&s.includes('Low'))return'Engine oil level should be corrected and checked for cause.';return'Service or repair should be planned.'}return'Plan this item for upcoming service or recheck.'}
function customerEducationText(row){const i=row.item,s=String(row.value||''),battery=batteryEducationText(i,s),road=roadTestEducationText(i,s),underbody=underbodyEducationText(i,s);if(battery)return battery;if(road)return road;if(underbody)return underbody;if(/Oil Service Opportunity|Engine Oil Condition|Engine Oil Leaks/.test(i))return'Engine oil creates a protective film between fast-moving metal parts while also carrying away heat, dirt, and combustion byproducts. As oil ages, runs low, or becomes contaminated, it cannot separate those metal surfaces as well. That increases friction and heat, builds sludge, and accelerates internal engine wear. If ignored long enough, the engine can start damaging itself from the inside and repairs can become much more expensive than the service itself.';if(/Brake Pad|Brake Service Opportunity|Brake Performance|Brake Pedal|Brake Noise|Brake Pulsation/.test(i))return'The brake pads are the friction material that press against the rotors to slow the vehicle. As the pads get thin, stopping distance can increase, brake noise can appear, and the backing plate can eventually contact the rotor. Waiting too long can turn a normal brake service into rotor damage, vibration, grinding, and reduced braking confidence.';if(/Tire Service Opportunity|Tire Condition|Tread Depth/.test(i))return s.includes('Sidewall Damage')?'The tire sidewall carries the tire structure and flexes every time the vehicle moves. Damage there is different from normal tread wear because the sidewall cannot be safely repaired in most cases. If ignored, the tire can lose strength, leak air, or fail suddenly, so replacement should be planned.':'Tires are the only part of the vehicle touching the road. Tread depth gives the tire room to move water out from under the contact patch. As tread gets low, wet-road stopping distance increases and traction drops. Planning tires before they are fully worn helps avoid poor wet traction, hydroplaning risk, and last-minute replacement decisions.';if(/Washer Fluid/.test(i))return'Washer fluid is a visibility item. It helps clear dirt, salt, bugs, road spray, and light ice from the windshield so the driver can see without stopping. Low fluid, leaks, or weak freeze protection may not mean the vehicle has a major mechanical failure, but it can become a real safety problem in rain, winter driving, or highway conditions when the windshield gets dirty quickly.';if(/Air Filter \/ Intake|Engine Air Filter/.test(i))return'The engine air filter keeps dirt and debris out of the intake while allowing the engine to breathe. When it becomes restricted, airflow readings and engine performance can be affected, and the engine may feel less responsive. If debris gets past a damaged or poorly sealed filter, it can contaminate sensitive intake parts and increase engine wear over time.';if(/Cabin Air Filter|Pollen/.test(i))return'The cabin air filter cleans the air entering the HVAC system. When it is dirty, airflow through the vents can drop, defrost performance can suffer, and dust or odors can circulate inside the cabin. Replacing it helps restore airflow, keeps the evaporator/blower area cleaner, and improves comfort for the people inside the vehicle.';if(/Coolant|Cooling|Radiator|Hoses|Water Pump|Thermostat/.test(i))return'The cooling system keeps engine temperature under control by moving heat away from the engine. Low coolant, leaks, weak components, or poor freeze protection can let the engine run too hot or leave it vulnerable in cold weather. If ignored, overheating can damage gaskets, plastic cooling parts, and internal engine components.';if(/Brake Fluid/.test(i))return'Brake fluid transfers pedal force through the hydraulic brake system. Over time it can absorb moisture, which lowers its boiling point and can contribute to brake fade under heat. Low or contaminated brake fluid can also point to wear or leaks. Ignoring it can reduce brake confidence and increase the chance of additional brake-system repairs.';if(/Power Steering/.test(i))return'Power steering fluid helps create hydraulic assist and lubricates steering components. Low or contaminated fluid can make the pump work harder, create noise, make steering feel heavy, and eventually damage the pump, rack, or hoses. Rechecking or servicing it helps protect steering assist and keeps the vehicle easier to control.';if(/Scan|Code|MIL|Check Engine/.test(i))return'The vehicle scan and warning-light check help show what the vehicle computers reported during the inspection. Codes do not automatically diagnose the failed part, but they point to systems that need attention. Ignoring active warning lights or major codes can allow drivability, emissions, or safety-related issues to continue unnoticed.';if(/Light|Headlight|Taillight|Marker|Hazard|Wiper|Glass|Windshield|Mirror/.test(i))return'These items affect what the driver can see and how well other drivers can see the vehicle. Lights, glass, mirrors, and wipers are simple safety items, but when they are not working correctly they can make bad weather, night driving, lane changes, and braking situations more risky.';return'This item was included because it can affect vehicle safety, reliability, comfort, or future repair cost. Reviewing it helps prioritize what should be handled now, what should be planned for the next service, and what should simply be monitored.'}
function batteryEducationText(i,s){if(/Battery Date \/ Age/.test(i))return'Battery age matters because the chemical plates inside the battery slowly degrade with heat cycles, vibration, charging cycles, and time. As a battery gets older, it can still show some voltage but have less reserve capacity and less cranking strength. That means the vehicle may start fine today but become more likely to have a slow crank or no-start during cold weather, short trips, or after sitting.';if(/Resting Battery Voltage/.test(i))return'Resting battery voltage is a quick snapshot of the battery state of charge before the charging system is helping it. A healthy, charged 12V battery is usually around the mid-12 volt range. A low reading can mean the battery is discharged, aging, or being drained by another issue. This reading should be rechecked after recharge because low charge and a weak battery can look similar during one inspection.';if(/Measured CCA/.test(i))return'Measured CCA is the tester estimate of how much starting current the battery can deliver compared with what it was rated to provide when new. A low measured CCA means the battery may not have enough strength for cold starts or high electrical demand, even if the lights and accessories still work.';if(/Rated CCA/.test(i))return'Rated CCA is the label rating used as the baseline for the battery test. Comparing measured CCA to rated CCA shows how much cranking strength the battery still has compared with its original specification. Without the rating, the tester result is less meaningful because there is no proper target to compare against.';if(/Battery Health \/ Load Test|Battery Test Result/.test(i))return'The battery test places the battery under a simulated load to see whether it can supply current when the vehicle actually needs it. This is more useful than voltage alone because a weak battery can sometimes show acceptable voltage but fail when asked to crank the engine. The result helps decide whether the battery is good, should be recharged and rechecked, or should be replaced.';if(/Battery Type/.test(i))return'Battery type matters because different batteries are built and charged differently. AGM, flooded lead-acid, and other battery styles can require different charging strategies. The wrong type can shorten battery life, create charging issues, or cause the vehicle battery management system to make poor decisions.';if(/Battery Brand \/ Size/.test(i))return'Battery size and label information help confirm that the battery physically fits, has the correct terminal layout, and has enough capacity for the vehicle. A battery that is too small or the wrong group size may crank weakly, sit loose in the tray, overload the charging system, or leave cables stretched in a way that can cause future problems.';if(/Correct Battery Installed/.test(i))return'This confirms whether the installed battery appears to match what the vehicle is designed to use. An incorrect battery can affect fitment, cranking power, reserve capacity, and charging behavior. It may still start the vehicle during the inspection, but it can create reliability problems later.';if(/Battery Programming Required/.test(i))return'Some vehicles need the new battery registered or programmed into the vehicle after replacement. That lets the charging system adjust for the battery age, capacity, and type. If programming is needed but not performed, the vehicle may overcharge or undercharge the battery, shortening battery life or causing electrical warnings.';if(/Battery Location|Battery Access \/ Serviceability/.test(i))return'Battery location and access affect how easy it is to inspect, test, jump start, or replace the battery. If access is restricted, condition may be harder to verify without removing covers or trim, and future service can take more time than a simple under-hood battery.';if(/Powertrain Type/.test(i))return'Powertrain type helps set expectations for the electrical inspection. Hybrid and plug-in hybrid vehicles can have different battery layouts, warning lights, cooling fans, and charging behavior than a standard gas vehicle, so identifying the setup helps keep the inspection notes accurate.';if(/Battery Physical Condition/.test(i))return'The battery case should be secure, dry, and free of swelling, cracks, or leakage. Physical damage can point to internal failure, overcharging, impact damage, or acid leakage. A compromised battery case can damage nearby components and may become unreliable without much warning.';if(/Terminals \/ Corrosion Condition|Battery Visual \/ Terminal \/ Tie-Down Condition/.test(i))return'Battery terminals are the main electrical connection between the battery and the vehicle. Corrosion, looseness, or poor contact creates resistance, which can cause slow starts, intermittent no-starts, warning lights, or charging problems. A clean, tight connection helps the battery and charging system work consistently.';if(/Battery Cable Condition/.test(i))return'Battery cables carry high current during starting and charging. Damage, corrosion under the insulation, loose ends, or poor routing can create voltage drop and heat. That can make a good battery act weak, cause intermittent electrical faults, or prevent the alternator from charging the battery properly.';if(/Battery Tie-Down Condition/.test(i))return'The battery tie-down keeps the battery from moving. If the battery is loose, vibration and impact can damage the internal plates, crack the case, loosen terminals, or stress the cables. A secure battery lasts longer and is safer during normal driving or a sudden stop.';if(/Jump Post Condition/.test(i))return'Jump posts give a safe place to connect a jump pack, charger, or test equipment when the battery is hidden or hard to reach. If the posts are missing, poorly marked, damaged, or hard to identify, roadside assistance and future testing can take longer and may increase the chance of connecting equipment incorrectly.';if(/Cranking Voltage/.test(i))return'Cranking voltage shows how far battery voltage drops while the starter is turning the engine. A large drop can point to a weak battery, high resistance in the cables, a starter drawing too much current, or an engine that is harder to crank. It helps connect the battery test result to how the vehicle actually starts.';if(/Alternator Charging Output|Charging/.test(i))return'Alternator charging output shows whether the vehicle is replenishing the battery while the engine runs. If charging voltage is too low, the battery may slowly discharge and leave the vehicle stranded. If it is too high, it can damage the battery and sensitive electronics. A normal output helps confirm the battery is being supported after start-up.';if(/Electrical Warning Lights Observed|Warning Lights Illuminate In Accessory Mode/.test(i))return'Electrical warning-light behavior helps confirm that the vehicle is communicating system concerns to the driver. Warning lights that stay on, fail to illuminate during bulb check, or appear unexpectedly can point to a system that needs more verification. This is an inspection observation, not a final diagnosis.';if(/Further Evaluation Recommended/.test(i))return'This means the inspection found a reason that the item could not be fully confirmed visually or with the basic inspection checks. Further evaluation may require removing covers, accessing hidden components, charging and retesting, or performing diagnostic steps beyond the inspection scope.';if(/High Voltage|Hybrid|Regenerative/.test(i))return'Hybrid electrical items are important because they affect how the vehicle starts, charges, assists the engine, and recovers energy during braking. Warning messages, abnormal fan noise, or regenerative braking concerns can reduce efficiency or point to a system that needs dedicated hybrid testing.';return /Battery|Voltage|Charging|Alternator/.test(i)?'The battery and charging system support starting, module memory, lights, accessories, and electronic controls. A concern here can show up as slow starts, warning lights, intermittent electrical behavior, or a dead battery. The inspection result helps decide whether the item is acceptable, should be rechecked, or should be serviced.':''}
function underbodyEducationText(i,s){if(/Ball Joint/.test(i))return'The ball joint is the pivot point between the control arm and the steering knuckle. It lets the wheel steer and move with the suspension at the same time. Wear, torn boots, or excessive movement can cause clunks, loose steering feel, uneven tire wear, and in severe cases loss of wheel control, so movement is the key safety concern.';if(/Lower Control Arm/.test(i))return'The lower control arm locates the wheel and holds suspension geometry under braking, turning, and bumps. Its bushings absorb movement while the arm keeps the tire positioned correctly. Worn bushings, bent arms, or joint movement can cause clunks, pulling, unstable braking, alignment changes, and rapid tire wear.';if(/Upper Control Arm|Wishbone|Camber Arm|Toe Arm|Trailing Arm/.test(i))return'This suspension arm helps position the wheel and maintain alignment angles as the vehicle moves. Worn bushings or joint movement can change camber or toe, which affects tire wear, stability, and how the vehicle tracks on the road. Small wear can become expensive if it ruins tires or stresses nearby parts.';if(/Tie Rod/.test(i))return'Tie rods connect the steering rack to the wheel knuckle. They control toe angle, which is one of the most important alignment settings for tire wear and straight tracking. A worn tie rod can create loose steering, clunks, wandering, or uneven tire wear, and excessive movement is a direct steering safety concern.';if(/Steering Rack Seals/.test(i))return'Steering rack seals keep power steering fluid inside the rack. Leaking seals can lower fluid level, create noise, reduce steering assist, and eventually damage the rack or pump. Even a small seep should be monitored because steering leaks usually worsen over time.';if(/Steering Rack Condition/.test(i))return'The steering rack converts steering wheel input into side-to-side movement at the tires. Play, leaks, damaged mounts, or abnormal movement can make the vehicle wander, feel loose, or respond poorly. Because the rack is central to steering control, any major concern should be prioritized.';if(/Steering System Wiring/.test(i))return'Steering wiring supports electric assist, steering sensors, and related warning systems on many vehicles. Damaged wiring or poor routing can cause warning lights, intermittent assist, or communication issues. It matters because modern steering systems often depend on electronics, not just mechanical parts.';if(/Shock/.test(i))return'Shocks and struts control spring movement so the tires stay planted on the road. When they leak or weaken, the vehicle can bounce, nose-dive, feel harsh or floaty, and take longer to settle after bumps. Poor damping also increases tire wear and can reduce braking and handling confidence.';if(/Spring/.test(i))return'Springs support the vehicle weight and establish ride height. A broken, sagging, or shifted spring can change alignment, reduce suspension travel, create noise, and make the vehicle sit unevenly. That can affect handling and put extra stress on shocks, tires, and suspension bushings.';if(/Sway Bar Link|Sway Bar Bushing|Sway Bar/.test(i))return'The sway bar helps control body roll during turns by linking the left and right suspension. Links and bushings secure it and allow controlled movement. Worn parts often create clunks over bumps and can make the vehicle lean or feel less stable during quick steering inputs.';if(/Subframe|Cradle/.test(i))return'The subframe or cradle is a major mounting structure for suspension, steering, or drivetrain parts. Corrosion, impact damage, loose mounting points, or repair evidence can affect alignment, strength, and how securely major components are held. This is more serious than a cosmetic underbody concern.';if(/Engine Mount/.test(i))return'Engine mounts hold the engine in position while absorbing vibration. When a mount collapses or tears, the engine can move excessively during acceleration, braking, or shifting. That can cause clunks, vibration, exhaust stress, hose strain, and drivetrain movement that feels worse over time.';if(/Transmission Mount/.test(i))return'The transmission mount supports the transmission and helps control drivetrain movement. A worn mount can cause clunks, vibration, harsh engagement, or stress on axles, exhaust parts, and wiring. It may feel like a shift quality issue even when the transmission itself is not the root cause.';if(/Axle/.test(i))return'CV axles transfer power to the wheels while allowing the suspension and steering to move. Torn boots let grease escape and dirt enter the joint, which can lead to clicking, vibration, and eventual axle failure. Catching a boot issue early can prevent replacing the entire axle assembly later.';if(/Driveshaft/.test(i))return'The driveshaft transfers power through the driveline. Wear in joints, center supports, or the shaft itself can create vibration, clunks, or noise under acceleration. Ignoring driveline vibration can damage seals, bearings, transfer cases, differentials, or transmission output components.';if(/Differential Leaks/.test(i))return'Differential fluid lubricates gears and bearings that handle high load. A leak can lower the fluid level and cause whining, bearing wear, gear damage, or overheating. Differential repairs can become expensive quickly, so leaks should be monitored or repaired before the fluid level becomes too low.';if(/Differential Wiring/.test(i))return'Differential wiring can support sensors, lockers, AWD controls, or electronic clutch systems. Damaged wiring may cause warning lights, inoperative AWD features, or incorrect system behavior. This is especially important on vehicles with electronically controlled driveline systems.';if(/Transfer Case Leaks/.test(i))return'The transfer case sends power to the front and rear driveline on AWD or 4WD vehicles. Leaks can lower fluid level and damage internal chains, gears, bearings, or clutches. A small leak can turn into a major driveline repair if the unit runs low on fluid.';if(/Transfer Case Wiring/.test(i))return'Transfer case wiring controls or monitors 4WD and AWD operation on many vehicles. Damage or corrosion can cause warning lights, shifting issues, or loss of drive-mode functions. The vehicle may still drive normally until the system is asked to engage.';if(/Transmission Leaks/.test(i))return'Transmission fluid cools, lubricates, and helps operate internal components. A leak can lead to low fluid, slipping, harsh shifting, delayed engagement, or internal damage. Transmission leaks should be taken seriously because low fluid can cause expensive damage quickly.';if(/Transmission Wiring/.test(i))return'Transmission wiring carries signals for solenoids, sensors, range switches, and control modules. Damage can cause shift concerns, warning lights, limp mode, or intermittent operation. Wiring concerns can mimic internal transmission problems, so they should be documented clearly.';if(/Frame \/ Unibody|Frame|Unibody|Jacking Points|Lift Points/.test(i))return'The frame, unibody, and lift points support the vehicle structure and provide safe places to raise it. Rust, impact damage, crushed lift points, or poor prior repairs can affect safety, alignment, and future serviceability. Damaged lift points can also make normal maintenance harder or unsafe.';if(/Surface Rust/.test(i))return'Surface rust is usually early corrosion on exposed metal. It may not mean the structure is weak yet, but it should be monitored because road salt and moisture can let it spread. Treating or monitoring surface rust early helps prevent it from becoming structural corrosion.';if(/Structural Rust|Underbody Rust/.test(i))return'Structural rust is corrosion that affects strength, mounting points, or load-bearing areas. This is more serious than surface rust because it can compromise suspension mounts, frame sections, brake/fuel line supports, and lift points. Structural rust can affect safety and repair feasibility.';if(/Fuel Tank Condition/.test(i))return'The fuel tank stores fuel and must stay securely mounted and physically protected. Dents, corrosion, damaged straps, or loose mounting can create odor, noise, service access issues, or future leak risk. Even without an active leak, tank condition matters because fuel system repairs can become urgent if damage worsens.';if(/Fuel Line Condition/.test(i))return'Fuel lines carry pressurized fuel from the tank toward the engine. Corrosion, wetness, rubbing, or damage can create fuel odor, drivability problems, or fire risk. Fuel line concerns should be treated carefully even when the leak is not actively dripping during inspection.';if(/Brake Fluid Lines/.test(i))return'Brake lines carry hydraulic pressure from the brake pedal to the wheels. Rust, wetness, or damage can weaken the line and reduce braking reliability. A brake line leak or severe corrosion can become a major safety issue because hydraulic pressure is what applies the brakes.';if(/Exhaust Manifold/.test(i))return'The exhaust manifold collects exhaust gases as they leave the engine. Cracks or leaks can create ticking noises, fumes, oxygen sensor errors, or heat damage nearby. Exhaust leaks near the engine can also allow fumes into areas where they may enter the cabin.';if(/Catalytic Converter/.test(i))return'The catalytic converter reduces harmful emissions and is part of the exhaust flow path. Damage, missing components, rattles, or restriction can cause noise, emissions failures, check-engine lights, and poor performance. It is also expensive, so condition and prior repair evidence matter.';if(/Mid Pipe|Muffler|Exhaust Leaks/.test(i))return'Exhaust pipes and mufflers carry exhaust away from the vehicle and control noise. Leaks can create fumes, rattles, louder operation, and failed emissions or safety inspections. Exhaust leaks can worsen as metal heats, cools, and corrodes.';if(/Exhaust Heat Shield/.test(i))return'Heat shields protect the body, wiring, fuel lines, and nearby components from exhaust heat. Loose shields often rattle, while missing shields can allow excessive heat into areas that were designed to be protected. They are small parts, but they prevent heat-related damage.';if(/Exhaust Hangers/.test(i))return'Exhaust hangers support the exhaust system while allowing some movement. Missing or torn hangers let the exhaust sag, rattle, contact the body, or stress joints and flex sections. A loose exhaust can turn a small hanger issue into broken pipes or leaks.';if(/Undertray|Splash Shield|Fasteners/.test(i))return'Undertrays and splash shields protect wiring, hoses, belts, and lower engine components from water, debris, and road impact. Missing fasteners or damaged panels can cause dragging noises, reduced protection, and parts hanging low enough to be damaged while driving.';if(/Underbody Damage|Underbody Prior Work Evidence/.test(i))return'Underbody damage or prior work evidence helps document what may have happened before this inspection. Scrapes, bent brackets, missing covers, non-factory hardware, or fresh repairs can point to impact history or areas that may need closer review during future service.';return /Suspension|Tie Rod|Control Arm|Ball Joint|Shock|Sway Bar|Steering|Alignment|Transmission|Differential|Transfer Case|Driveline|Axle|Driveshaft|Frame|Underbody|Exhaust|Fuel Tank|Fuel Line/.test(i)?'This underbody item affects how the vehicle is supported, steered, driven, protected, or serviced. Problems underneath can show up as noise, leaks, vibration, tire wear, poor handling, or higher repair cost if they are left alone. The inspection helps separate normal wear from items that should be monitored or planned.':''}
function roadTestEducationText(i,s){if(/Acceleration|Throttle Response/.test(i))return'This checks whether the vehicle responds normally when the accelerator is pressed. The customer wants the vehicle to move smoothly and predictably, without hesitation, surging, stumbling, or a delayed reaction. If the response feels abnormal, it can make normal merging, passing, and city driving less confidence-inspiring and may point to a drivability issue that needs more testing.';if(/Transmission Shift Quality/.test(i))return'This checks how the transmission feels when the vehicle goes into gear and shifts while driving. A normal transmission should engage without a hard bang, long delay, slipping feeling, or sudden flare in engine speed between gears. If shifting feels harsh, delayed, or inconsistent, the vehicle may still drive, but the concern should be reviewed before it becomes a larger transmission or driveline issue.';if(/Engine Temperature Stability/.test(i))return'Temperature stability confirms the engine stayed in its expected operating range during the drive. A vehicle can look fine cold but show cooling-system weakness once it is under load. Rising temperature, fan concerns, or overheating behavior can point to coolant flow, radiator, thermostat, fan, or leak concerns.';if(/Vibrations/.test(i))return'Vibrations during a road test can come from tires, wheels, axles, driveshafts, mounts, suspension, or drivetrain components. Noting when the vibration happens, such as acceleration, braking, cruising, or turning, helps narrow down the system that should be reviewed next.';if(/Brake Performance|Brake Pedal Feel|Brake Performance \/ Pedal Feel/.test(i))return'This checks how confidently the vehicle slows down and how the brake pedal feels to the driver. A soft, low, hard, pulsating, or uneven pedal can point to brake wear, air or moisture in the hydraulic system, rotor issues, or other brake concerns. Good brake feel is important for predictable stopping.';if(/Brake Noise|Brake Pulsation/.test(i))return'Brake noise or pulsation during the drive helps confirm whether the braking system is quiet and smooth under real use. Squeals, grinding, clunks, or pedal/steering vibration can point to worn pads, rotor variation, loose hardware, or suspension movement that may not be obvious while parked.';if(/Parking Brake Operation/.test(i))return'The parking brake is a backup holding system that keeps the vehicle from rolling when parked. Checking operation helps confirm it applies, releases, and holds normally. A weak or inoperative parking brake can be a safety issue on hills and can also indicate cable, caliper, shoe, or electronic parking brake concerns.';if(/Steering Response/.test(i))return'This checks whether the vehicle turns predictably when the steering wheel is moved. The steering should feel connected, smooth, and controlled, without looseness, binding, wandering, or delayed reaction. If the steering response feels abnormal, the vehicle can feel harder to place in the lane and may need steering, suspension, tire, or alignment review.';if(/Alignment Tracking/.test(i))return'This checks whether the vehicle drives straight without needing constant correction. If the vehicle pulls left or right, drifts, or the steering wheel sits off-center while driving straight, it can be caused by alignment, tire pressure, tire wear, suspension wear, or prior impact. Even when it is not an immediate safety issue, poor tracking can make the vehicle tiring to drive and wear tires faster.';if(/Ride Comfort \/ Harshness/.test(i))return'Ride comfort shows how the suspension absorbs bumps and road texture. A harsh, bouncy, floaty, or unsettled ride can point to worn shocks, springs, bushings, mounts, tires, or suspension geometry issues. This matters because ride quality also affects tire contact and driver confidence.';if(/Suspension Noise/.test(i))return'Suspension noise during the drive can reveal movement that is hard to find while the vehicle is stationary. Clunks, rattles, squeaks, or knocks over bumps can point to bushings, links, ball joints, mounts, struts, shocks, or loose hardware. Matching the noise to the driving condition helps prioritize the next inspection step.';if(/Wheel Bearing Noise/.test(i))return'Wheel bearing noise often sounds like a growl, hum, or roar that changes with road speed or weight transfer. A worn bearing can affect noise, wheel stability, and ABS sensor readings. Catching bearing noise early helps prevent further hub, tire, or safety concerns.';if(/Highway Stability/.test(i))return'Highway stability checks how the vehicle behaves at higher speeds. Wandering, vibration, floating, pulling, or instability can point to tires, alignment, suspension, steering, aerodynamics, or prior repair issues. This matters because small concerns can feel much more serious at highway speed.';if(/Cabin Noise During Drive/.test(i))return'Cabin noise helps document wind noise, rattles, squeaks, trim noises, or vibration that the customer may notice every day. These items may not stop the vehicle from driving, but they affect comfort and can sometimes point to loose trim, seals, glass, suspension, or prior repair areas.';if(/Transfer Case Operation/.test(i))return'Transfer case operation confirms that 4WD or AWD-related functions engage and behave normally when checked. Abnormal noises, binding, warning lights, or failure to engage can point to fluid, actuator, wiring, driveline, or control-system concerns.';if(/Cruise Control Operation/.test(i))return'Cruise control operation confirms the vehicle can hold speed and respond to driver inputs correctly. If it does not engage or cancels unexpectedly, it can point to brake switch, steering wheel button, sensor, module, or warning-system issues.';if(/Driver Assist Operation|Safety Systems Operation/.test(i))return'Driver assist and safety-system checks confirm whether available support features appear to operate normally during the inspection. These systems can depend on cameras, radar sensors, steering angle data, brake inputs, and warning modules, so warning messages or unavailable features should be documented clearly.';if(/Warning Messages During Drive/.test(i))return'Warning messages during the drive are important because some systems only flag a concern once the vehicle is moving. A message does not diagnose the failed part by itself, but it tells us which system needs review and helps separate a stored history item from an active driving concern.';if(/HVAC Operation/.test(i))return'HVAC operation confirms the heating, cooling, fan, and vent controls work during normal use. This affects comfort, windshield defrosting, and moisture control inside the cabin. Weak airflow, temperature problems, or control issues can point to filters, actuators, refrigerant, blower, or control-system concerns.';if(/Low Speed Maneuvering|Parking Lot Turns/.test(i))return'Low-speed turns and parking-lot maneuvers put load on steering, suspension, axles, mounts, and driveline components in a way straight driving may not. Clicking, binding, clunks, or shudder during these maneuvers can reveal CV axle, steering, suspension, mount, or AWD/4WD concerns.';if(/Reverse Operation/.test(i))return'Reverse operation checks whether the vehicle engages reverse smoothly and backs up normally. Delayed engagement, harsh engagement, slipping, shudder, or warning messages can point to transmission, driveline, mount, camera/sensor, or control-system concerns.';if(/Steering Wheel Button Operation|Vehicle Feature Operation/.test(i))return'This confirms driver controls and common vehicle features respond during normal use. Non-working buttons or features may seem minor, but they can affect convenience, safety settings, audio/phone controls, cruise functions, or driver-assist access.';if(/Idle After Road Test/.test(i))return'Idle after the road test checks how the vehicle behaves once it is fully warm. Rough idle, stalling, high idle, smoke, smells, or warning lights after driving can reveal heat-related issues that may not appear during a cold start.';if(/Hot Restart/.test(i))return'Hot restart confirms the vehicle starts normally after being driven and heat soaked. Some starter, battery, fuel, sensor, or engine concerns only show up when components are warm, so this is a useful check after the road test.';if(/Cooling Fans/.test(i))return'Cooling fan operation after a drive helps confirm the vehicle can manage heat at low speeds and after stopping. A fan concern can lead to overheating in traffic even if the vehicle stays cool on the highway.';if(/Abnormal Odors After Road Test/.test(i))return'Odors after a drive can reveal leaks, overheating, burning oil, coolant, fuel, brake drag, clutch smell, or exhaust concerns. Smells are important because they can appear before a leak or heat issue becomes obvious visually.';if(/Post Test Drive Codes/.test(i))return'Post-road-test codes show whether the vehicle set or retained warning information after being driven. Some faults only appear once monitors run or systems are under load. This helps document whether the road test introduced any new inspection concern.';if(/Road Test Limitation/.test(i))return'A road test limitation means the drive could not fully reproduce every normal driving condition. Traffic, weather, vehicle condition, road speed, or safety concerns can limit what can be verified. The result should be read as what was observed within those inspection conditions.';return roadTestItem(i)?'The road test checks how the vehicle behaves under real driving conditions. Some concerns only appear when the vehicle is moving, warming up, braking, turning, shifting, or operating under load. This result helps connect the visual inspection to how the vehicle actually feels on the road.':''}
function customerLineGroups(records,scope=''){const out=[];records.forEach(r=>{const label=customerLineGroupLabel(r,scope),g=out.find(x=>x.label===label);g?g.records.push(r):out.push({label,records:[r]})});const order=['General Results','Front Lighting','Side Lighting','Rear Lighting','Body','Glass','Wipers','Left Front','Right Front','Right Rear','Left Rear','Front Suspension','Rear Suspension','Frames / Subframes','Steering','Driveline','Exhaust','Frame & Body','Engine Mounts','Filters','Safety','Tires','Engine','Battery','Controls & Features','Lights & Warnings'];return out.sort((a,b)=>{const ai=order.indexOf(a.label),bi=order.indexOf(b.label);return (ai<0?99:ai)-(bi<0?99:bi)})}
function customerLineGroupLabel(r,scope=''){const i=r.item;if(scope==='Tires'||scope==='Brakes')return wheelCornerLabel(i);if(scope==='Steering')return'Steering';if(scope==='Suspension'){if(/Front|LF |RF /.test(i))return'Front Suspension';if(/Rear|LR |RR /.test(i))return'Rear Suspension';return'Frames / Subframes'}if(scope==='Engine Mounts')return'Engine Mounts';if(scope==='Driveline')return'Driveline';if(scope==='Body'){if(/Exhaust/.test(i))return'Exhaust';return'Frame & Body'}return customerSubgroup(r)}
function wheelCornerLabel(i){if(/LF /.test(i))return'Left Front';if(/RF /.test(i))return'Right Front';if(/RR /.test(i))return'Right Rear';if(/LR /.test(i))return'Left Rear';return'General Results'}
function customerSubgroup(r){const i=r.item,c=r.cat;if(customerTitle(r.sec).includes('Maintenance Opportunities')){if(i==='Recall Status')return'General Results';if(/Wiper/.test(i))return'Wiper Blades';if(/Air Filter|Cabin Air Filter/.test(i))return'Filters';if(/Tire|Brake/.test(i))return'Safety';if(/Oil|Fluid|Coolant|Power Steering|Spark Plug/.test(i))return'Engine';if(/Transmission|Differential|Transfer Case/.test(i))return'Driveline';if(/Battery/.test(i))return'Battery';return'General Results'}if(c==='Exterior Lighting Operation'){if(/Headlight|Fog/.test(i))return'Front Lighting';if(/Side Marker|Hazard/.test(i))return'Side Lighting';return'Rear Lighting'}if(/Wiper/.test(i))return'Wipers';if(c==='Paint and Body'||c==='Final Checks')return'';if(/Measurement|Brake Pad|Voltage|CCA|DOT|Moisture|Freezing|Tire|Pressure/.test(i))return'Tires';if(/Light|Headlight|Taillight|Marker|Hazard|Brake Light|Warning/.test(i))return'Lights & Warnings';if(/Window|Mirror|Glass|Windshield/.test(i))return'Glass';if(/Seat|Seat Belt|Child Lock|Air Filter|Odor|Water|Moisture|Carpet|Headliner|Trim|Console|Glovebox|Cargo|Trunk/.test(i))return'Filters';if(/Lock|Horn|Control|Infotainment|USB|Outlet|Release|Sunroof|HVAC|Feature|Button|Operation/.test(i))return'Controls & Features';if(/Leak|Fluid|Oil|Coolant|Fuel|Brake Fluid|Power Steering|Washer|Reservoir|Line/.test(i))return'Engine';if(/Paint|Body|Rust|Corrosion|Repair|Panel|VIN|Sticker|Bumper|Hood|Door|Fender|Quarter|Rim|Trim/.test(i)||/Exterior|Paint/.test(c))return'Body';if(/Scan|Code|Readiness|Odometer|MIL/.test(i))return'Scan & Readiness';if(/Battery|Charging|Alternator|Terminal|Cable|CCA|Cranking|Jump/.test(i))return'Battery';if(/Engine|Belt|Timing|Air Filter|Cold Start|Idle|Noise|Smoke|Mount/.test(i))return'Engine Area';if(/Steering|Suspension|Control Arm|Ball Joint|Shock|Sway|Axle|Driveshaft|Differential|Transmission|Frame|Underbody|Exhaust|Fastener|Undertray/.test(i))return'Driveline';return'General Results'}
function customerItemLabel(item){return {'Oil Service Opportunity':'Engine Oil Service','Brake Fluid Service Opportunity':'Brake Fluid Service','Coolant Service Opportunity':'Cooling System Service','Power Steering Service Opportunity':'Power Steering Fluid Service','Engine Air Filter Opportunity':'Engine Air Filter','Cabin Air Filter Opportunity':'Cabin Air Filter','Wiper Blade Opportunity':'Wiper Blades','Tire Service Opportunity':'Tires','Brake Service Opportunity':'Brakes','Battery Service Opportunity':'Battery','Transmission Service Opportunity':'Transmission Service','Front Differential Service Opportunity':'Front Differential Service','Transfer Case Service Opportunity':'Transfer Case Service','Rear Differential Service Opportunity':'Rear Differential Service','Spark Plug / Tune-Up Opportunity':'Spark Plugs / Tune-Up'}[item]||item}
function goNextCustomerSection(currentTitle=''){const rendered=[...document.querySelectorAll('[data-customer-section]')].map(x=>x.getAttribute('data-customer-title')).filter(Boolean),fallback=['Vehicle Background','Required Maintenance','Exterior','Interior','Electrical','Engine','Wheels & Brakes','Underbody','Road Test'],order=rendered.length?rendered:fallback,activeTitle=currentTitle||document.activeElement?.closest?.('[data-customer-title]')?.getAttribute('data-customer-title')||'',idx=order.indexOf(activeTitle),nextTitle=order[idx+1];if(!nextTitle){document.getElementById('customer-print-footer')?.scrollIntoView({behavior:'smooth',block:'start'});return}window.dispatchEvent(new CustomEvent('customer-open-section',{detail:{title:nextTitle,scroll:true}}))}
function LineItemIcon({row}){const t=lineIconType(row.item,row.files?.length),common={fill:'none',stroke:'currentColor',strokeWidth:2,strokeLinecap:'round',strokeLinejoin:'round'};return <span className="mr-2 inline-grid h-7 w-7 shrink-0 place-items-center rounded-lg bg-orange-400/20 text-orange-100"><svg viewBox="0 0 24 24" className="h-5 w-5" aria-hidden="true">{t==='photo'?<><rect x="4" y="7" width="16" height="12" rx="2" {...common}/><path d="M9 7l1.5-2h3L15 7" {...common}/><circle cx="12" cy="13" r="3" {...common}/></>:t==='glass'?<><path d="M5 18L8 6h8l3 12z" {...common}/><path d="M9 9h6" {...common}/></>:t==='light'?<><path d="M5 8h7l5 4-5 4H5z" {...common}/><path d="M18 8l3-2M19 12h3M18 16l3 2" {...common}/></>:t==='hood'?<><path d="M4 17h16L17 6H7z" {...common}/><path d="M8 16l2-8M16 16l-2-8" {...common}/></>:t==='bumper'?<><path d="M4 13c2-4 14-4 16 0v4H4z" {...common}/><path d="M7 17v2M17 17v2" {...common}/></>:t==='door'?<><path d="M7 4h10v16H7z" {...common}/><path d="M15 12h-2" {...common}/></>:t==='wheel'?<><circle cx="12" cy="12" r="7" {...common}/><circle cx="12" cy="12" r="2" {...common}/><path d="M12 5v5M12 14v5M5 12h5M14 12h5" {...common}/></>:t==='electric'?<path d="M13 2L5 14h6l-1 8 8-12h-6z" {...common}/>:<><rect x="5" y="6" width="14" height="12" rx="2" {...common}/><path d="M8 10h8M8 14h5" {...common}/></>}</svg></span>}
function lineIconType(item,hasPhoto){if(hasPhoto)return'photo';if(/Glass|Window|Windshield|Mirror/.test(item))return'glass';if(/Light|Warning|Headlight|Taillight/.test(item))return'light';if(/Hood/.test(item))return'hood';if(/Bumper|Diffuser/.test(item))return'bumper';if(/Door|Quarter|Fender/.test(item))return'door';if(/Tire|Brake|Rim|Pad/.test(item))return'wheel';if(/Battery|Voltage|CCA|Charging/.test(item))return'electric';return'general'}
function CustomerResultRow({row,anchor=true}){const[open,setOpen]=useState(false),[full,setFull]=useState(null),hasPhotos=row.files.length>0,props=anchor?{id:`customer-row-${id(row.k)}`}:{},photoLabel=hasPhotos?`View Media (${row.files.length})`:'',label=customerItemLabel(row.item);return <div {...props} className="grid lg:grid-cols-[1fr_auto] gap-3 p-4 bg-neutral-950/75 hover:bg-orange-500/5 scroll-mt-24 transition"><div className="flex items-start gap-3 min-w-0"><span className={`mt-1 h-8 w-8 shrink-0 rounded-xl border grid place-items-center font-black ${customerTone(row.level)}`}><StatusGlyph level={row.level}/></span><div className="min-w-0"><p className="font-semibold text-white">{label}</p><p className="text-sm text-orange-100/70 mt-1">{row.cat}</p><p className="mt-2 text-neutral-100 whitespace-pre-line leading-relaxed">{row.text}</p></div></div><div className="flex lg:flex-col items-start lg:items-end gap-2"><span className={`rounded-full border px-3 py-1 text-xs font-bold ${customerTone(row.level)}`}>{customerResultText(row.level)}</span>{hasPhotos&&<button type="button" onClick={()=>setOpen(!open)} className="rounded-lg border border-orange-300/30 px-2 py-1 text-[11px] text-orange-100 hover:bg-orange-500/20">{open?'Hide Media':photoLabel}</button>}</div>{open&&hasPhotos&&<div className="lg:col-span-2 grid sm:grid-cols-2 lg:grid-cols-3 gap-3 pt-2">{row.files.map((p,i)=><figure key={i} className="rounded-2xl border border-orange-300/20 bg-black p-2"><MediaThumb media={p} label={label} onOpen={()=>setFull(p)} className="h-48 w-full"/><figcaption className="mt-2 text-xs text-neutral-400">{p.name||p.label||label}</figcaption></figure>)}</div>}<PhotoLightbox photo={full} label={label} close={()=>setFull(null)}/></div>}
function MediaThumb({media,label,onOpen,className='h-48 w-full'}){const content=media?.error?<div className={`${className} grid place-items-center rounded-xl border border-red-400/40 bg-red-600/10 p-2 text-center text-xs text-red-100`}>{media.error}</div>:isVideoMedia(media)?<video src={media.url} muted playsInline preload="metadata" className={`${className} rounded-xl object-cover border border-orange-300/30 bg-black`}/>:<img src={media?.url} alt={media?.label||label} className={`${className} rounded-xl object-cover border border-orange-300/30`}/>;return onOpen&&!media?.error?<button type="button" onClick={onOpen} className="block w-full text-left">{content}</button>:content}
function PhotoLightbox({photo,label,close}){if(!photo)return null;const video=isVideoMedia(photo);return <div className="fixed inset-0 z-[100] grid place-items-center bg-black/90 p-4" role="dialog" aria-modal="true" onClick={close}><div className="max-h-full w-full max-w-6xl" onClick={e=>e.stopPropagation()}><div className="mb-3 flex items-center justify-between gap-3"><p className="text-sm font-bold text-white">{photo.name||photo.label||label}</p><button type="button" onClick={close} className="rounded-xl bg-white px-4 py-2 text-sm font-black text-black">Close</button></div>{video?<video src={photo.url} controls playsInline className="max-h-[82vh] w-full rounded-2xl bg-black object-contain"/>:<img src={photo.url} alt={photo.label||label} className="max-h-[82vh] w-full rounded-2xl object-contain"/>}</div></div>}
function CustomerPhotoReport({photos}){const[full,setFull]=useState(null),groups=Object.entries(photos||{}).filter(([,v])=>v?.length).reduce((acc,[k,v])=>{const [sec,cat,item]=k.split('|'),g=`${customerTitle(sec)} · ${cat}`;(acc[g] ||= []).push({item,files:v});return acc},{}),total=Object.values(groups).flat().reduce((n,x)=>n+x.files.length,0);return !total?null:<Card className="bg-neutral-950/95"><div className="flex items-center justify-between gap-3"><div><p className="text-xs uppercase tracking-[0.2em] text-orange-200">Media Documentation</p><h2 className="text-2xl font-bold mt-1">All Attached Media</h2></div><span className="rounded-full border border-green-400/40 bg-green-600/15 px-3 py-1 text-sm">{total} file{total===1?'':'s'}</span></div><div className="space-y-6 mt-5">{Object.entries(groups).map(([group,items])=><section key={group}><h3 className="font-bold mb-3">{group}</h3><div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{items.flatMap(({item,files})=>files.map((p,i)=>{const label=customerItemLabel(item);return <figure key={`${item}-${i}`} className="rounded-2xl bg-black p-3 border border-white/10"><MediaThumb media={p} label={label} onOpen={()=>setFull(p)} className="w-full h-56"/><figcaption className="mt-2 text-sm"><b>{label}</b>{p.name?` · ${p.name}`:''}</figcaption></figure>}))}</div></section>)}</div><PhotoLightbox photo={full} label="Media Documentation" close={()=>setFull(null)}/></Card>}
function Summary({title,overall,findings,scope,sections=SEC,data={},photos={}}){const cats=(sections.find(([s])=>s===scope)?.[1]||[]).map(([c])=>c),scoped=findings.filter(x=>x.sec===scope),name=customerTitle(scope),flat=/Vehicle History|Electrical|Vehicle Scan/.test(name),[open,setOpen]=useState(false),[sig,setSig]=useState(0),sr=sectionResult(scoped);return <Card className="p-0 overflow-hidden"><button onClick={()=>setOpen(!open)} className="w-full flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3 p-5 border-b border-orange-300/20 text-left"><span className="text-2xl font-bold">{customerTitle(title)}</span><span className="flex items-center gap-3 text-sm text-neutral-300"><Dot level={sr.level}/><b className="text-white">{sr.text}</b><span>{open?'▲':'▼'}</span></span></button>{open&&<div className="p-4 sm:p-6"><div className="space-y-4"><Info label={overall} value={sr.text} level={sr.level}/>{name.includes('Electrical')?<><BatteryCustomerSummary data={data}/><FindingList findings={scoped} photos={photos}/></>:flat?cats.map(cat=>{const f=scoped.filter(x=>x.cat===cat),lv=worst(f.map(x=>x.severity),'green');return <div key={cat} className={`rounded-2xl border p-4 ${lv==='red'?'border-red-400/50':lv==='yellow'?'border-yellow-300/50':'border-green-400/40'} bg-neutral-950`}><div className="flex items-center gap-2 mb-3"><Dot level={lv}/><h3 className="font-bold">{cat}</h3></div><FindingList findings={f} photos={photos}/></div>}):<><button onClick={()=>setSig(Date.now())} className={mini}>Expand All</button><div className="grid lg:grid-cols-2 gap-3">{cats.map(cat=>{const f=scoped.filter(x=>x.cat===cat),lv=worst(f.map(x=>x.severity),'green');return <SumRow signal={sig} key={cat} label={cat} findings={f} photos={photos} level={lv}/>})}</div></>}</div></div>}</Card>}
function SumRow({label,findings,photos,level,signal}){const[open,setOpen]=useState(false);useEffect(()=>{if(signal)setOpen(true)},[signal]);return <div className={`rounded-2xl border ${level==='red'?'border-red-400/50':level==='yellow'?'border-yellow-300/50':'border-green-400/40'} bg-neutral-950 overflow-hidden`}><button onClick={()=>setOpen(!open)} className="w-full flex items-center justify-between p-4 text-left"><span className="flex items-center gap-2"><Dot level={level}/><b>{label}</b></span><span>{open?'▲':'▼'}</span></button>{open&&<div className="px-4 pb-4"><FindingList findings={findings} photos={photos}/></div>}</div>}
function FindingList({findings,photos={}}){return findings.length?<div className="space-y-3">{findings.map(x=><Finding key={x.k||x.label} finding={x} files={photos[x.k]||[]}/>)}</div>:<p className="text-sm text-neutral-200 whitespace-pre-line leading-relaxed">Looks good based on the inspection. No notable concerns were recorded.</p>}
function Finding({finding,files=[]}){const[open,setOpen]=useState(false),[full,setFull]=useState(null),label=customerItemLabel(finding.label);return <div className="text-sm text-neutral-200 leading-relaxed"><p><span className="mr-1">•</span><b>{label}:</b> {finding.status}</p>{files.length>0&&<button type="button" onClick={()=>setOpen(!open)} className={`${mini} mt-2`}>{open?'Hide Media':`View Media (${files.length})`}</button>}{open&&<div className="grid sm:grid-cols-2 gap-3 mt-3">{files.map((p,i)=><figure key={i} className="rounded-xl bg-black p-2 border border-orange-300/20"><MediaThumb media={p} label={label} onOpen={()=>setFull(p)} className="w-full h-48"/><figcaption className="mt-2 text-xs text-neutral-400">{p.label}</figcaption></figure>)}</div>}<PhotoLightbox photo={full} label={label} close={()=>setFull(null)}/></div>}
function PhotoReport({photos}){const[full,setFull]=useState(null),groups=Object.entries(photos||{}).filter(([,v])=>v?.length).reduce((acc,[k,v])=>{const [sec,cat,item]=k.split('|');const g=`${sec} · ${cat}`;(acc[g] ||= []).push({item,files:v});return acc},{});return !Object.keys(groups).length?null:<Card><h2 className="text-2xl font-bold mb-1">Media Documentation</h2><div className="space-y-5 mt-4">{Object.entries(groups).map(([group,items])=><section key={group}><h3 className="font-bold mb-3">{group}</h3><div className="grid md:grid-cols-2 gap-4">{items.flatMap(({item,files})=>files.map((p,i)=><figure key={`${item}-${i}`} className="rounded-2xl bg-neutral-950 p-3"><MediaThumb media={p} label={item} onOpen={()=>setFull(p)} className="w-full h-64"/><figcaption className="mt-2 text-sm"><b>{item}</b>{p.name?` · ${p.name}`:''}</figcaption></figure>))}</div></section>)}</div><PhotoLightbox photo={full} label="Media Documentation" close={()=>setFull(null)}/></Card>}
function Final(p){return <Card id="final-assessment"><h2 className="text-2xl font-bold mb-4">Final Assessment</h2><Field label="Recommended Action"><Buttons opts={ACT} val={p.action} setVal={p.setAction}/></Field><Field label="Estimated Risk Level"><Buttons opts={RISK} val={p.risk} setVal={p.setRisk}/></Field><div className="grid md:grid-cols-2 gap-4"><TextArea label="Monitor / Recheck Items" value={finalText(p.findings,'yellow')}/><TextArea label="Recommended Attention" value={finalText(p.findings,'red')}/><TextArea label="Technician Notes"/><TextArea label="Recommended Repairs"/></div></Card>}
function BatteryCustomerSummary({data}){const system=batterySystemSummary(data),replace=batteryReplacementSummary(data),cards=batteryCustomerCards(data);return <div className="space-y-4"><div className="grid md:grid-cols-2 gap-3"><Info label="Battery System Summary" value={system.text} level={system.level}/><Info label="Battery Replacement Recommendation" value={replace.text} level={replace.level}/></div><div className="grid lg:grid-cols-2 gap-3">{cards.map(c=><Info key={c.label} label={c.label} value={c.value} level={c.level}/>)}</div></div>}

function opts(i){if(maintenanceItem(i))return['Not Needed','Plan Ahead','Recommended','Further Diagnosis Needed','Due Soon','Due Now','Could Not Verify'];if(i==='Glass Condition')return['Pass','Chip','Crack','Could Not Verify'];if(i==='Road Test Limitation')return['No Limitation','Traffic Limited Test','Weather Limited Test','Vehicle Concern Limited Test','Unable to Verify'];if(i==='Transmission Shift Quality')return['Normal Engagement','Normal Shift','Monitor','Delayed Engagement','Harsh Engagement','Harsh Shift','Slipping / Flare Observed','Unable to Verify'];if(i==='Reverse Operation')return['Normal Reverse','Monitor','Delayed Engagement','Harsh Engagement','Unable to Verify'];if(i==='Brake Noise')return['No Brake Noise','Monitor','Squeal','Grinding','Clunk','Unable to Verify'];if(i==='Alignment Tracking')return['Tracks Straight','Steering Wheel Centered','Monitor','Slightly Off-Center','Significantly Off-Center','Pulls Left','Pulls Right','Unable to Verify'];if(i==='Ride Comfort / Harshness')return['Normal Ride','Monitor','Harsh Ride','Excessive Bounce','Unable to Verify'];if(i==='Cabin Noise During Drive')return['Normal Cabin Noise','Monitor','Wind Noise','Rattle','Squeak','Unable to Verify'];if(i==='Warning Messages During Drive')return['No Warning Messages','Monitor','Warning Message Observed','Feature Unavailable','Unable to Verify'];if(['Transfer Case Operation','Cruise Control Operation','Driver Assist Operation'].includes(i))return['Pass','Monitor','Fail','Unable to Verify'];if(roadTestItem(i))return['Pass','Monitor','Fail','Unable to Verify'];if(under(i))return['Pass','Monitor','Fail'];if(i.includes('Inner Fender Liner'))return['Pass','Monitor','Fail','Could Not Verify'];if(i==='Fuel Cap Condition')return['Present / Secure','Loose','Damaged','Missing','Could Not Verify'];if(i==='Powertrain Type')return['Gas','Hybrid','Plug-In Hybrid'];if(i==='Battery Location')return['Engine Bay','Trunk','Interior','Unable to Verify'];if(i==='Battery Type')return BAT;if(i==='Correct Battery Installed')return['Correct','Incorrect'];if(i==='Battery Programming Required')return['No','Yes - Verified','Yes - Not Verified','Unable to Verify'];if(i==='Battery Access / Serviceability')return['Easy Access','Restricted Access','Special Procedure Required'];if(i==='Battery Physical Condition')return['Good','Swollen','Damaged','Leaking','Unable to Verify'];if(i==='Terminals / Corrosion Condition')return['Secure','Light Corrosion','Loose Terminal','Needs Attention','Unable to Verify'];if(['Battery Cable Condition','Battery Tie-Down Condition'].includes(i))return['Pass','Monitor','Fail','Unable to Verify'];if(i==='Jump Post Condition')return['Pass','Fail','Clearly Marked','Hard To Identify','Missing / Unclear'];if(i==='Visible Aftermarket Electrical Add-ons')return['None Observed','Present - Clean Install','Present - Concern','Could Not Verify'];if(i==='Warning Lights Illuminate In Accessory Mode')return['Warning Lights Illuminate Normally','Warning Lights Do Not Illuminate','Could Not Verify'];if(i==='Battery Health / Load Test')return['Pass','Fail','Not Tested'];if(i==='Battery Test Result')return['Good','Good-Recharge','Replace Soon','Replace Now','Bad Cell','Not Tested'];if(i==='Electrical Warning Lights Observed')return['None','Battery Light','Hybrid Warning','Multiple Warning Lights','Could Not Verify'];if(i==='Further Evaluation Recommended')return['No','Yes - Access / Disassembly Required','Could Not Verify'];if(['High Voltage Warning Lights','Hybrid Warning Message Observed'].includes(i))return['None','Present','Could Not Verify'];if(i==='Hybrid Battery Cooling Fan Noise')return['Normal','Noisy','Unable to Verify'];if(i==='Regenerative Braking Operation')return['Pass','Monitor','Fail','Unable to Verify'];if(i==='MIL / Check Engine Light Status')return['Off','On','Could Not Verify'];if(i.includes('Key Fob'))return['Pass','Fail','Unable to Verify'];if(i==='Odometer Consistency')return['Consistent','Mismatch Observed','Could Not Verify'];if(i==='Readiness Status')return['Ready','Not Ready','Recently Cleared / Incomplete','Could Not Verify'];if(i==='Possible Recent Code Clear')return['No Evidence Observed','Possible / Incomplete Readiness','Could Not Verify'];if(i==='Under Bonnet Access Limitation')return['No Limitation','Covers Restrict Visibility','Further Disassembly Required','Could Not Verify'];if(i==='Engine Bay Cleanliness')return['Clean / Normal','Dusty / Aged','Heavy Dirt / Oil Residue','Freshly Detailed','Could Not Verify'];if(i==='Engine Cover / Underhood Covers')return['Secure','Loose / Missing Fasteners','Damaged','Could Not Verify'];if(i==='Under Bonnet Prior Work Evidence')return['None Obvious','Recent Repair Evidence','Missing Covers / Fasteners','Aftermarket Parts Observed','Could Not Verify'];if(i==='Post Test Drive Codes')return['Present','Not Present','Unable to Verify'];if(i.includes('Leaks'))return['None','Small Seepage','Leaking','Could Not Verify'];if(fluidCondition(i))return fluidConditionOpts;if(i==='Belts Condition')return['Serviceable','Wear / Cracking - Recommend Replace','Fail','Could Not Verify'];if(i==='Belt Slack')return['Normal','Loose','Could Not Verify'];if(i==='Timing Chain Slack Present')return['Timing Chain Slack Not Present','Timing Chain Slack Present','Could Not Verify'];if(i==='Coolant Reservoir / Cap Condition')return['Level Visible / OK','Low','Overfilled','Reservoir Hard To Read','Leak / Staining Observed','Damaged / Missing Cap','Could Not Verify'];if(['Radiator','Hoses','Water Pump','Thermostat'].includes(i))return['Pass','Recommend to Replace','Fail','Could Not Verify'];if(i==='Air Filter / Intake Airbox Condition')return['Clean','Dirty','Secure','Loose / Damaged','Missing Clips / Fasteners','Aftermarket Intake Observed','Could Not Verify'];if(i==='Wiring Condition')return['Serviceable','Damaged','Could Not Verify'];if(i==='Mounting Security')return['Secure','Loose'];if(i==='Terminals Condition')return['Pass','Monitor','Needs Attention'];if(i==='Cold Start')return['Normal Start','Slow / Long Crank','No Start','Could Not Verify'];if(i==='Idle Quality')return['Normal','Rough Idle','High Idle','Stalling','Could Not Verify'];if(i==='Engine Noise')return['Normal','Abnormal Noise Observed','Knock / Tick Observed','Could Not Verify'];if(i==='Exhaust Smoke')return['Clear','White','Blue','Black','Gray','Could Not Verify'];if(i==='Bearing Noise / Play')return['Pass','Monitor','Fail'];if(['VIN Plate Condition','Door Jamb Sticker Present'].includes(i))return['Present / Legible','Missing','Unable to Verify'];if(i==='Spare Tire / Inflator Kit')return['Spare Present','Inflator Kit Present','Missing','Unable to Verify'];if(IC(i))return GFB;if(i==='Cabin Air Filter (Pollen Filter)')return['Clean','Dirty','Unable to Verify'];if(i==='Interior Odor')return['None','Light','Strong'];if(['Water Intrusion Signs','Spare Tire Well Moisture'].includes(i))return['No','Yes'];if(i.includes('Trim & Clips'))return['Pass','Monitor','Fail'];if(i.includes('Wiper'))return['Pass','Recommend to Replace','Fail'];return PF}
function drop(i){return {'Paint Condition Overall':['Excellent','Very Good','Good','Fair','Poor','Severely Neglected','Catastrophic'],'Paint Match Consistency':['Yes','No'],'Clear Coat Condition':['Good','Fair','Bad'],'Rust / Corrosion':['None','Minimal','Light','Moderate','Significant','Extensive'],'Body Repair Evidence':['No Evidence Observed','Evidence Present'],'Panel Gap / Alignment Overview':['Normal','Minor Misalignment','Significant Misalignment']}[i]||null}
function testValue(r,level){const {item,cat}=r,desired=level==='fail'?'red':level==='monitor'?'yellow':'green';if(scheduleMaintenanceItem(item))return level==='pass'?'Recommended Mileage:90000|Not Needed':level==='monitor'?'Recommended Mileage:62000|Due Soon':'Recommended Mileage:52000|Due Now';if(tireMeasurementItem(item))return testTreadValue(level);if(tireItem(item))return testTireValue(level);if(item==='Battery Brand / Size')return level==='pass'?'Interstate H6 AGM label visible':level==='monitor'?'Battery label partially visible':'Battery label could not be verified';if(item==='Battery Date / Age')return level==='pass'?'2024 date code visible':level==='monitor'?'Older date code observed':'Unable to Verify';if(item==='Scan Report Photo')return level==='pass'?'Uploaded':'Not Performed';if(item==='Coolant Condition')return level==='pass'?'37|Fluid Level OK':level==='monitor'?'25|Fluid Level OK|Service May Be Due|Discoloration':'12|Low|Service May Be Due';if(item==='Brake Fluid Condition')return level==='pass'?'1|Fluid Level OK':level==='monitor'?'2|Service May Be Due':'4|Low|Discoloration';if(voltageItem(item))return testVoltageValue(item,level);if(item==='Measured CCA')return level==='pass'?'650':level==='monitor'?'520':'390';if(item==='Rated CCA')return'700';if(LIGHT[item])return LIGHT[item].map(x=>`${x}:${level==='fail'?'Fail':'Pass'}`).join('|');if(vehicleHistoryItem(item))return testHistoryValue(item,level);if(SET.body.has(item))return level==='pass'?'Good':level==='monitor'?'Fair|Scratch':'Bad|Dent|Misaligned';if(SET.rim.has(item))return level==='pass'?'Pass':level==='monitor'?'Curb Rash':'Fail';if(SET.glass.has(item))return level==='pass'?'Pass':level==='monitor'?'Chip':'Crack';if(item==='Terminals / Corrosion Condition')return level==='pass'?'Secure':level==='monitor'?'Secure|Light Corrosion':'Loose Terminal|Needs Attention';if(item==='Jump Post Condition')return level==='pass'?'Pass|Clearly Marked':level==='monitor'?'Pass|Hard To Identify':'Fail|Missing / Unclear';if(item==='Code Status Summary')return level==='pass'?'No Codes Observed':level==='monitor'?'Minor Codes Observed|Pending':'Major Codes Observed|Stored|Permanent';if(item==='Transmission Shift Quality')return level==='pass'?'Normal Engagement|Normal Shift':level==='monitor'?'Monitor|Harsh Shift':'Fail|Slipping / Flare Observed';if(item==='Alignment Tracking')return level==='pass'?'Tracks Straight|Steering Wheel Centered':level==='monitor'?'Monitor|Slightly Off-Center':'Fail|Significantly Off-Center';if(fluidCondition(item))return level==='pass'?'Clean|Fluid Level OK':level==='monitor'?'Fluid Level OK|Service May Be Due|Discoloration':'Low|Discoloration';if(['Fuel Line Condition','Brake Fluid Lines'].includes(item))return level==='pass'?'Serviceable':level==='monitor'?'Surface Rust':'Wetness / Seepage|Damage Observed';if(detailLikeItem(item)||under(item))return testOptionValue(item,desired);const dd=drop(item);if(dd)return pickByLevel(item,dd,desired);return pickByLevel(item,opts(item),desired)}
function testTireValue(level){const d=level==='pass'?['3523','Pressure OK','Lug Nuts Present','Sidewall OK']:level==='monitor'?['3419','Underfilled','Lug Nuts Present','Sidewall OK']:['1017','Overfilled','Lug Nuts Missing','Sidewall Damage'];return`DOT:${d[0]}|${d[1]}|${d[2]}|${d[3]}`}
function testTreadValue(level){const d=level==='pass'?['8','8','8']:level==='monitor'?['6','6','6']:['3','3','3'];return`Inner:${d[0]}|Center:${d[1]}|Outer:${d[2]}`}
function testVoltageValue(item,level){if(item==='Resting Battery Voltage')return level==='pass'?'12.7':level==='monitor'?'12.5':'12.1';if(item==='Cranking Voltage')return level==='pass'?'10.2|Normal Start':level==='monitor'?'9.5|Slow / Long Crank':'9.0|Slow / Long Crank';return level==='pass'?'14.2|Pass':level==='monitor'?'13.3|Not Tested':'12.4|Fail'}
function testHistoryValue(item,level){if(item==='Carfax Status')return level==='pass'?'Carfax Available':level==='monitor'?'Carfax Not Available':'Could Not Verify';if(item.startsWith('Ownership'))return level==='pass'?'One Owner|Clean Title|No Accidents Reported|Personal Use':level==='monitor'?'Multiple Owners|Clean Title|No Accidents Reported':'Title Concern|Accident Reported|Fleet / Rental / Commercial Use';if(item==='Recall Status')return level==='pass'?'No Open Recalls Reported':level==='monitor'?'Recall Status Not Verified':'Open Recall Reported';if(item==='Service / Timing History')return level==='pass'?'Service Records Available|Major / Timing Service Recorded':level==='monitor'?'Could Not Verify':'Service Records Not Available|Major / Timing Service Unknown';if(item==='Modifications / Warranty')return level==='pass'?'No Modifications Reported|Warranty Active':level==='monitor'?'Warranty Status Unknown':'Modifications Reported|Warranty Expired';return level==='pass'?'No Disclosure Notes':level==='monitor'?'Disclosure Notes Present|Disclosure Note: Seller disclosure should be reviewed.':'Disclosure Notes Present|Disclosure Note: Significant disclosure item recorded for testing.'}
function detailLikeItem(item){return tieRodItem(item)||axleItem(item)||controlArmItem(item)||ballJointItem(item)||shockItem(item)||mountItem(item)||exhaustDetailItem(item)||fastenerUndertrayItem(item)||['Fuel Tank Condition','Underbody Prior Work Evidence','Jacking Points / Lift Points','Air Filter / Intake Airbox Condition','Coolant Reservoir / Cap Condition','Glovebox Condition'].includes(item)}
function testOptionValue(item,desired){const o=opts(item);return pickByLevel(item,o,desired)}
function pickByLevel(item,options,desired){const exact=options.find(x=>valueSeverity(item,x)===desired||sev(x)===desired);if(exact)return exact;if(desired==='red')return options.find(x=>/Fail|Bad|Poor|Damaged|Missing|Concern|Leaking|Loose|No Start|On|Evidence Present|Incorrect|Low/.test(x))||pickByLevel(item,options,'yellow');if(desired==='yellow')return options.find(x=>/Monitor|Recommend|Verify|Limited|Fair|Light|Moderate|Not Tested|Service May Be Due|Unknown|Hard/.test(x))||pickByLevel(item,options,'green');return options.find(x=>GREEN.has(x)||x==='Pass')||options[0]||''}
function testNote(r,level){if(['Exterior Lighting Operation','Final Checks'].includes(r.cat))return'';if(level==='pass')return'Customer preview test fill: item checked with no concern recorded.';if(level==='monitor')return'Customer preview test fill: item should be monitored or reviewed with the customer.';return'Customer preview test fill: concern recorded so the customer report shows a needs-attention result.'}
