function one(a){return a[Math.floor(Math.random()*a.length)]}
function randomDigits(n){return Array.from({length:n},()=>Math.floor(Math.random()*10)).join('')}
function randomTestRecord(){const cars=[['2021 Porsche 911 Turbo S','WP0AD2A9XMS257911','3.8L Twin-Turbo Flat-6','PDK','Shark Blue','$350'],['2017 Acura NSX','19UNC1B05HY000777','JNC1','9-Speed DCT','Nouvelle Blue Pearl','$350'],['2016 Dodge Viper ACR','1C3BDEDZ6GV100645','8.4L V10','Tremec 6-Speed','Viper Red','$350'],['2018 Audi R8 V10 Plus','WUAKBAFX8J7900610','5.2L V10','S Tronic','Suzuka Gray','$350'],['2022 Cadillac CT5-V Blackwing','1G6D25R66N0864122','LT4 Supercharged V8','6-Speed Manual','Electric Blue','$350'],['2020 Mercedes-AMG GT C','WDDYK8AA9LA028777','M178 V8 Biturbo','AMG Speedshift DCT','Solarbeam Yellow','$350'],['2021 Lexus LC 500','JTHHP5AY4MA102500','2UR-GSE V8','10-Speed Auto','Infrared','$350'],['2023 Lotus Emira First Edition','SCCLEKAX3PHN10522','2GR-FE Supercharged V6','6-Speed Manual','Seneca Blue','$350'],['2019 Chevrolet Corvette Z06','1G1YU2D68K5600627','LT4 Supercharged V8','7-Speed Manual','Sebring Orange','$350'],['2021 Toyota GR Supra 3.0 Premium','WZ1DB0C05MW042020','B58B30O1','ZF 8-Speed','Renaissance Red 2.0','$350'],['2014 Ferrari 458 Spider','ZFF68NHA8E0201458','F136 V8','7-Speed F1 DCT','Rosso Corsa','$350'],['2020 Nissan GT-R Premium','JN1AR5EF8LM100777','VR38DETT','6-Speed DCT','Bayside Blue','$350']],c=one(cars),names=['Jordan Vale','Maya Sterling','Nico Pierce','Sofia Cross','Dante Mercer','Elena Voss','Marcus Stone','Zara Reid'],shops=['Apex Motor Gallery','Velocity Auto Group','Northline Exotics','Summit Performance Motors','Blacktop Collectors','Heritage Sport Imports'];return {'Customer Name':one(names),'Phone Number':'224-652-7264','Vehicle Year / Make / Model':c[0],'VIN':c[1]||`GN${randomDigits(15)}`,'Mileage':(8000+Math.floor(Math.random()*52000)).toLocaleString(),'Engine Code':c[2],'Color':c[4],'Transmission Code':c[3],'Price':c[5],'Dealership':one(shops),'Inspection Date':new Date().toISOString().slice(0,10),'Technician':'Grease Nomads Technician'}}
const VIDEO_LIMIT=20*1024*1024;
function isVideoMedia(p){return String(p?.type||'').startsWith('video/')||p?.kind==='video'||/\.(mp4|mov|m4v|webm)$/i.test(String(p?.name||''))}
function filePhoto(file,label){return new Promise(resolve=>{const kind=file.type?.startsWith('video/')?'video':file.type?.startsWith('image/')?'image':'file';if(kind==='video'&&file.size>VIDEO_LIMIT)return resolve({label,name:file.name,url:'',type:file.type,size:file.size,kind,error:'Video is too large. Keep clips under 20 MB.'});const fallback=()=>{const r=new FileReader();r.onload=()=>resolve({label,name:file.name,url:r.result,type:file.type,size:file.size,kind});r.onerror=()=>resolve({label,name:file.name,url:'',type:file.type,size:file.size,kind,error:'Could not read this file.'});r.readAsDataURL(file)};if(kind!=='image')return fallback();const r=new FileReader();r.onload=()=>{const img=new Image();img.onload=()=>{try{const max=1600,scale=Math.min(1,max/Math.max(img.width,img.height)),w=Math.max(1,Math.round(img.width*scale)),h=Math.max(1,Math.round(img.height*scale)),canvas=document.createElement('canvas'),ctx=canvas.getContext('2d');canvas.width=w;canvas.height=h;ctx.drawImage(img,0,0,w,h);resolve({label,name:file.name,url:canvas.toDataURL('image/jpeg',.72),type:'image/jpeg',size:file.size,kind:'image'})}catch{resolve({label,name:file.name,url:String(r.result||''),type:file.type,size:file.size,kind})}};img.onerror=()=>resolve({label,name:file.name,url:String(r.result||''),type:file.type,size:file.size,kind});img.src=String(r.result||'')};r.onerror=fallback;r.readAsDataURL(file)})}
async function saveReportPayload(payload,status='completed'){const res=await fetch('/api/reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...payload,status})}),text=await res.text();if(!res.ok)throw new Error(`report save failed (${res.status})`);try{return JSON.parse(text)}catch{throw new Error('report save did not return JSON. Make sure you are running the backend server, not only the Vite dev server.')}}
async function saveFinalReport(payload){return saveReportPayload(payload,'completed')}
async function saveDraftReport(draft){return saveReportPayload({...draft,status:'draft',createdAt:new Date().toISOString()},'draft')}
function reportUrl(r){const path=r?.id?`/report/${r.id}/the-vehicles-inspection-result`:r?.publicPath||'/report/';return new URL(path,location.origin).href}
function dateShort(v){if(!v)return'--';try{return new Date(v).toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}catch{return String(v)}}
function draftSort(a,b){const af=futureInspection(a.record||{}),bf=futureInspection(b.record||{});if(af!==bf)return af?-1:1;return String(a.record?.['Inspection Date']||a.savedAt||'').localeCompare(String(b.record?.['Inspection Date']||b.savedAt||''))}
function futureInspection(r={}){const d=r['Inspection Date'];if(!d)return false;const today=new Date().toISOString().slice(0,10);return d>=today}
function bulkActions(title,cats,set){const apply=vals=>Object.entries(vals).forEach(([k,v])=>set(k,v));if(customerTitle(title).includes('Electrical'))return[{label:'Pass Battery Visuals',run:()=>apply(bulkValues(title,cats,batteryVisualDefault))},{label:'Battery Not Accessible',run:()=>apply(bulkValues(title,cats,batteryNotAccessibleDefault))}];return[]}
function bulkValues(sec,cats,pick){return Object.fromEntries(rows([[sec,cats]]).map(r=>[r.k,pick(r.item,r.cat)]).filter(([,v])=>v))}
function section1Default(item,cat){if(isNum(item)||item.includes('DOT')||textField(item)||item==='Battery Date / Age')return'';if(SET.body.has(item))return'Good';if(SET.rim.has(item)||SET.glass.has(item))return'Pass';if(LIGHT[item])return LIGHT[item].map(x=>`${x}:Pass`).join('|');if(SET.light.has(item))return'Pass';if(item==='Tire Matching')return'Matches Door Placard';const dd=drop(item);if(dd)return dd[0];const o=opts(item);return o.includes('Pass')?'Pass':o[0]||''}
function section2Default(item){if(isNum(item)||item.includes('DOT')||textField(item))return'';if(IC(item))return'Good';if(item==='Interior Odor')return'None';if(['Water Intrusion Signs','Spare Tire Well Moisture'].includes(item))return'No';if(item==='Cabin Air Filter (Pollen Filter)')return'Clean';const o=opts(item);return o.includes('Pass')?'Pass':o[0]||''}
function batteryVisualDefault(item,cat){if(cat!=='Battery Inspection')return'';return {'Battery Physical Condition':'Good','Terminals / Corrosion Condition':'Secure','Battery Cable Condition':'Pass','Battery Tie-Down Condition':'Pass','Jump Post Condition':'Not Equipped / Applicable'}[item]||''}
function batteryNotAccessibleDefault(item,cat){if(cat==='Battery Inspection')return {'Battery Date / Age':'Unable to Verify','Battery Access / Serviceability':'Restricted Access','Battery Physical Condition':'Unable to Verify','Terminals / Corrosion Condition':'Unable to Verify','Battery Cable Condition':'Unable to Verify','Battery Tie-Down Condition':'Unable to Verify','Jump Post Condition':'Not Equipped / Applicable'}[item]||'';return''}
function rows(s=SEC){return s.flatMap(([sec,cats])=>cats.flatMap(([cat,items])=>items.map(item=>({sec,cat,item,k:key(sec,cat,item)}))))}
function done(r,d){const v=String(d[r.k]||'').trim();return !!v&&(!LIGHT[r.item]||lightOK(r.item,v))||maintenanceItem(r.item)&&!!autoMaintenance(r.item,d)}
function rowVisible(mode,r,p){const q=String(p.search||'').trim().toLowerCase();if(q&&!`${r.sec} ${r.cat} ${r.item}`.toLowerCase().includes(q))return false;if(mode==='full')return true;if(mode==='incomplete')return !done(r,p.data);const v=p.data[r.k]||'',hasPhoto=!!p.photos[r.k]?.length;return photoReq(r.item,v)&&!hasPhoto}
function safeFindingsOf(d,active=null){try{return findingsOf(d||{},active)}catch(e){console.error('findings failed',e);return[]}}
function findingsOf(d,active=null){return Object.entries(d).filter(([k])=>!active||active.has(k)).map(([k,v])=>{const [sec,cat]=k.split('|'),item=k.split('|').pop(),severity=item==='Measured CCA'?ccaTone(d,k,v):valueSeverity(item,v),body=SET.body.has(item)&&['yellow','red'].includes(severity);return{k,sec,cat,label:body?item+' Cosmetic / Body Condition':item,status:statusText(sec,item,v,severity,body,d,k),severity}}).filter(x=>['yellow','red'].includes(x.severity)&&!raw(x.label))}
function statusText(sec,item,v,severity,body,d,k){const name=customerTitle(sec);if(verifyOnly(v))return verifyText(v);if(String(v).includes('Not Performed'))return notPerformedText(item);return body?bodyStatus(v):item==='Coolant Condition'?coolantStatus(v):name.includes('Maintenance Opportunities')?maintenanceStatus(item,v,severity):name.includes('Interior Condition')?interiorStatus(item,v,severity):name.includes('Electrical')?electricalStatus(item,v,severity,d,k):generalStatus(item,v,severity,name)}
function photoMissing(d,p,active=null){return Object.entries(d).filter(([k,v])=>{const i=k.split('|').pop();return (!active||active.has(k))&&photoReq(i,v)&&!(p[k]||[]).length}).map(([k])=>photoLabel(k.split('|').pop()))}
function photoReq(i,v){const s=String(v||'');return !!s&&/(^|\||:)(Fail|Bad)(\||$)|(^|\|)(Monitor|Needs Monitor)(\||$)/.test(s)}
function photoLabel(i){return LIGHT[i]?i+' photo required':i}
