function draftId(record,stamp,type='ppi'){const base=String(record.VIN||record['Vehicle Year / Make / Model']||stamp||Date.now()).replace(/[^a-z0-9]+/gi,'-').toLowerCase()||String(Date.now());return `${type}-${base}`}
