function jobName(record,stamp){return [record['Vehicle Year / Make / Model']||'Untitled vehicle',record.VIN?`VIN ${record.VIN}`:'',record.Dealership||'',stamp?`Saved ${stamp}`:''].filter(Boolean).join(' - ')}
function jobLabel(j){return `${j.status||'Draft'} - ${j.name||'Untitled job'}`}
function draftSignature(x={}){const photoSummary=Object.fromEntries(Object.entries(x.photos||{}).map(([k,v])=>[k,(v||[]).map(p=>[p.name,p.size,p.type,String(p.url||'').length])])),body={record:x.record||{},data:x.data||{},photos:photoSummary,notes:x.notes||{},action:x.action||'',risk:x.risk||'',hybrid:!!x.hybrid};return JSON.stringify(body)}
function cacheReport(rep){if(!rep?.id)return;try{sessionStorage.setItem(REPORT_KEY+rep.id,JSON.stringify(rep));localStorage.setItem(REPORT_KEY+rep.id,JSON.stringify(rep))}catch{try{const light={...rep,photos:{}};sessionStorage.setItem(REPORT_KEY+rep.id,JSON.stringify(light));localStorage.setItem(REPORT_KEY+rep.id,JSON.stringify(light))}catch{}}}
function loadCachedReport(id){for(const store of [sessionStorage,localStorage]){try{const raw=store.getItem(REPORT_KEY+id);if(raw)return JSON.parse(raw)}catch{}}return null}
function batteryCustomerCards(data){const measuredKey=Object.keys(data||{}).find(k=>k.endsWith('|Measured CCA'))||'',rec=batteryTestRecommendation(data),test=['Battery Health / Load Test','Battery Test Result','Resting Battery Voltage','Measured CCA','Rated CCA'].map(i=>resultLine(data,i,measuredKey)).filter(Boolean),visual=['Battery Physical Condition','Terminals / Corrosion Condition','Battery Cable Condition','Battery Tie-Down Condition','Jump Post Condition'].map(i=>resultLine(data,i,measuredKey)).filter(Boolean),running=['Cranking Voltage','Alternator Charging Output','Electrical Warning Lights Observed','Further Evaluation Recommended','Visible Aftermarket Electrical Add-ons'].map(i=>resultLine(data,i,measuredKey)).filter(Boolean),id=['Powertrain Type','Battery Location','Battery Type','Battery Brand / Size','Battery Date / Age','Correct Battery Installed','Battery Programming Required','Battery Access / Serviceability'].map(i=>resultLine(data,i,measuredKey)).filter(Boolean),hybrid=['High Voltage Warning Lights','Hybrid Battery Cooling Fan Noise','Regenerative Braking Operation','Hybrid Warning Message Observed'].map(i=>resultLine(data,i,measuredKey)).filter(Boolean),cards=[{label:'Battery Test Results',value:[`Recommended battery test result: ${rec.result}.`,rec.note,...test].join('\n'),level:rec.level},{label:'Battery Visual Condition',value:visual.length?visual.join('\n'):'No battery visual results were entered.',level:worst(['Battery Physical Condition','Terminals / Corrosion Condition','Battery Cable Condition','Battery Tie-Down Condition','Jump Post Condition'].map(i=>batteryLevel(data,i)),'neutral')},{label:'Starting & Charging Results',value:running.length?running.join('\n'):'No starting or charging results were entered.',level:worst(['Cranking Voltage','Alternator Charging Output','Electrical Warning Lights Observed','Further Evaluation Recommended','Visible Aftermarket Electrical Add-ons'].map(i=>batteryLevel(data,i)),'neutral')},{label:'Battery Identification & Access',value:id.length?id.join('\n'):'No battery identification details were entered.',level:worst(['Correct Battery Installed','Battery Programming Required','Battery Access / Serviceability'].map(i=>batteryLevel(data,i)),'neutral')}];if(hybrid.length)cards.push({label:'Hybrid System Results',value:hybrid.join('\n'),level:worst(['High Voltage Warning Lights','Hybrid Battery Cooling Fan Noise','Regenerative Braking Operation','Hybrid Warning Message Observed'].map(i=>batteryLevel(data,i)),'neutral')});return cards}
function resultLine(data,item,measuredKey=''){const v=val(data,item);if(!v)return'';if(item==='Measured CCA')return`${item}: ${numOnly(v)} CCA${ccaNote(data,measuredKey,numOnly(v))?` (${ccaNote(data,measuredKey,numOnly(v))})`:''}`;if(item==='Rated CCA')return`${item}: ${numOnly(v)} CCA`;if(voltageItem(item)){const n=numOnly(v),flags=numFlags(v);return`${item}: ${n?`${n} V`:''}${flags.length?`${n?' / ':''}${displayValue(flags.join('|'))}`:''}`}return`${item}: ${displayValue(v)}`}
function batteryPhotoItem(i,v){const s=String(v||'');return ['Battery Physical Condition','Terminals / Corrosion Condition','Battery Cable Condition','Battery Tie-Down Condition','Jump Post Condition','Correct Battery Installed','Battery Test Result','Electrical Warning Lights Observed','High Voltage Warning Lights','Hybrid Warning Message Observed'].includes(i)&&/(Swollen|Damaged|Leaking|Needs Attention|Fail|Incorrect|Replace Now|Bad Cell|Multiple Warning Lights|Present|Missing)/.test(s)}
function verifyOnly(v){const parts=A(String(v||'')).filter(Boolean);return parts.length>0&&parts.every(x=>['Could Not Verify','Unable to Verify','Unable to Verify Without Disassembly'].includes(x))}
function verifyText(v){return A(String(v||'')).filter(Boolean).join(' / ')}
function displayValue(v){return verifyOnly(v)?verifyText(v):fmt(v)}
function clean(s){if(verifyOnly(s))return verifyText(s);return s.replaceAll('Fail','Service or repair recommended').replaceAll('Bad','Poor condition noted').replaceAll('Monitor','Monitor condition').replaceAll('Curb Rash','Curb rash noted').replaceAll('Sidewall Damage','Sidewall damage noted').replaceAll('Crack','Crack noted').replaceAll('Missing','Missing or not verified').replaceAll('Evidence Present','Evidence observed')}
function notPerformedText(item){return`${customerItemLabel(item)} was not performed during inspection due to limitations.`}
function generalStatus(item,v,severity,section=''){const s=clean(fmt(v));if(tireItem(item)){if(String(v).includes('Sidewall Damage'))return`Tire condition: ${s}. Sidewall damage means tire replacement is recommended.`;return`Tire condition: ${s}. ${severity==='green'?'No tire condition concern was recorded.':'This tire item should be reviewed and planned as needed.'}`}if(tireMeasurementItem(item)){const p=['Inner','Center','Outer'].map(x=>tireVal(v,x)&&`${x} ${tireVal(v,x)}/32nd`).filter(Boolean).join(', ');return`Tread depth result: ${p||s}. ${severity==='red'?'Replacement should be planned based on the recorded depth.':severity==='yellow'?'Plan ahead for tire replacement based on the recorded depth.':'Tread depth was in the acceptable range.'}`}if(item.includes('Brake Pad'))return`Brake pad measurement: ${numOnly(v)} mm. ${severity==='red'?'Brake service should be planned based on the recorded measurement.':severity==='yellow'?'Plan ahead for brake service based on the recorded measurement.':'Brake pad measurement was in the acceptable range.'}`;if(item==='Air Filter / Intake Airbox Condition')return`Engine air filter/intake result: ${s}. ${severity==='red'?'Filter replacement or intake service should be planned.':severity==='yellow'?'This intake item should be planned or rechecked.':'No intake service need was recorded.'}`;if(item==='Cabin Air Filter (Pollen Filter)')return interiorStatus(item,v,severity);if(fluidCondition(item))return`${customerItemLabel(item)} result: ${s}. ${severity==='red'?'This fluid item should be planned.':severity==='yellow'?'This fluid item should be planned or rechecked.':'No fluid concern was recorded.'}`;if(/Light|Glass|Wiper|Fuel Cap|Rim|Fender Liner|Brake|Safety/.test(item+' '+section))return`${customerItemLabel(item)} result: ${s}. ${severity==='red'?'This safety-related item should be addressed.':severity==='yellow'?'This safety-related item should be planned or rechecked.':'No concern was recorded for this safety item.'}`;return`${customerItemLabel(item)} result: ${s}. ${severity==='red'?'This item should be addressed.':severity==='yellow'?'This item should be planned or rechecked.':'No concern was recorded for this item.'}`}
const worst=(a,d='green')=>a.includes('red')?'red':a.includes('yellow')?'yellow':a.includes('green')?'green':d,sectionResult=f=>{const lv=worst(f.map(x=>x.severity),'green');return{level:lv,text:lv[0].toUpperCase()+lv.slice(1)}};
function summary(f){return f.length?f.map(x=>'• '+x.label+': '+x.status).join(String.fromCharCode(10)):'Looks good based on the inspection. No notable concerns were recorded.'}
function finalText(f,lvl){const t=f.filter(x=>x.severity===lvl).map(x=>x.label+': '+x.status).join(String.fromCharCode(10));return t||'No items recorded in this category.'}
function customerRecord(r,data={},photos={},inspectionType='ppi'){const value=data[r.k]||autoMaintenance(r.item,data,inspectionType)?.result||'',level=customerLevel(r,data,value,inspectionType),body=SET.body.has(r.item)&&['yellow','red'].includes(level),text=value?statusText(r.sec,r.item,value,level,body,data,r.k):'Not recorded during this inspection.',files=photos[r.k]||[];return{...r,inspectionType,value,level:level==='neutral'?'neutral':level,text,files}}
function customerLevel(r,data,value,inspectionType='ppi'){if(!String(value||'').trim())return'neutral';const base=r.item==='Measured CCA'?ccaTone(data,r.k,value):valueSeverity(r.item,value);return inspectionType==='ppi'?base:servicePriorityLevel(r,value,base)}
function servicePriorityLevel(r,value,base){if(base!=='red')return base;if(verifyOnly(value))return'yellow';return serviceSafetyConcern(r,value)?'red':'yellow'}
function serviceSafetyConcern(r,value){const item=r.item||'',cat=r.cat||'',sec=customerTitle(r.sec||''),ctx=item+' '+cat+' '+sec,s=String(value||''),susp=/Tie Rod|Ball Joint|Control Arm|Shock|Sway Bar|Suspension|Subframe|Cradle|Mount/.test(ctx);if(susp)return /Excessive Movement/.test(s);if(/Engine Oil/.test(ctx)&&/Low|Due Now/.test(s))return true;if(/Air Filter|Cabin Air Filter|Pollen|Filter Opportunity/.test(ctx)&&/Dirty|Due Now/.test(s))return true;if(/Major Codes Observed|Warning Light On|Multiple Warning Lights|No Start|Stalling|Overheating|Slipping|Grinding|Active Leak|Leaking|Wetness \/ Seepage|Fuel Tank Leaks|Fuel Line|Brake Fluid Lines|Bad Cell|Replace Now|Permanent Codes Observed|Structural Rust|Tank Damage Observed/.test(s))return true;return /Brake|Steering|Axle|Tire|Tread|Engine Temperature|Transmission Shift|Reverse Operation|Fuel|Frame|Road Test|Driveline/.test(ctx)&&/Fail|Needs Attention|Loose|Damaged|Low|Sidewall Damage|Dry Rot|Significant|Replace Now|Due Now|No Start|Timing Chain Slack Present/.test(s)}
function customerGroups(records,inspectionType='ppi'){const pick=(title,type='mini')=>makeCustomerGroup(title,records.filter(r=>customerGroupTitle(r,inspectionType)===title),type,inspectionType),order=inspectionType==='quick'?[['Required Maintenance'],['Safety'],['Interior','interior'],['Electrical'],['Engine'],['Underbody','underbody-cards'],['Road Test']]:[['Vehicle Background'],['Required Maintenance'],['Exterior','exterior'],['Interior','interior'],['Electrical'],['Engine'],['Wheels & Brakes'],['Underbody','underbody'],['Road Test']];return order.map(([title,type])=>pick(title,type||'mini')).filter(g=>g.records.length)}
function makeCustomerGroup(title,records,type='mini',inspectionType='ppi'){const mapped=records.map(r=>({...r,cat:customerGroupCat(title,r,inspectionType)})),cats=[...new Set(mapped.map(r=>r.cat))].sort((a,b)=>customerCatIndex(title,a)-customerCatIndex(title,b)).map(c=>[c]);return{title,type,inspectionType,records:mapped,cats}}
function wheelBrakeItem(r){const i=r.item,c=r.cat,name=customerTitle(r.sec);return name.includes('Exterior Condition')&&(/Tire|Rim|Brake Pad|Inner Fender Liner/.test(i)||i==='Tire Matching')||name.includes('Road Test')&&c==='Brake Evaluation'}
function customerGroupTitle(r,inspectionType='ppi'){const name=customerTitle(r.sec);if(name.includes('Maintenance Opportunities'))return'Required Maintenance';if(inspectionType==='quick'&&r.item==='Fuel Cap Condition')return'Interior';if(inspectionType==='quick'&&name.includes('Exterior Condition'))return'Safety';if(name.includes('Maintenance Opportunities'))return'Required Maintenance';if(wheelBrakeItem(r))return'Wheels & Brakes';if(name.includes('Vehicle History'))return'Vehicle Background';if(name.includes('Exterior Condition'))return'Exterior';if(name.includes('Interior Condition'))return'Interior';if(name.includes('Electrical')||name.includes('Vehicle Scan'))return'Electrical';if(name.includes('Under Bonnet')&&r.cat==='Strut Towers / Mounts')return'Underbody';if(name.includes('Under Bonnet'))return'Engine';if(name.includes('Underbody'))return'Underbody';if(name.includes('Road Test'))return'Road Test';return name||'Road Test'}
function customerGroupCat(group,r,inspectionType='ppi'){if(group==='Required Maintenance')return customerSubgroup(r);if(group==='Safety')return safetyCustomerCat(r);if(group==='Interior'&&inspectionType==='quick'&&r.item==='Fuel Cap Condition')return'Interior Final Checks';if(group==='Exterior')return exteriorCustomerCat(r);if(group==='Wheels & Brakes')return wheelBrakeCustomerCat(r);if(group==='Engine')return engineCustomerCat(r);if(group==='Underbody'&&inspectionType==='quick')return quickUnderbodyCat(r);if(group==='Electrical'){const name=customerTitle(r.sec);return name.includes('Vehicle Scan')||r.cat==='Scan Check'?'Scan & Readiness':'Battery, Electrical & Charging'}return r.cat}
function exteriorCustomerCat(r){const i=r.item,c=r.cat;if(c==='Exterior Lighting Operation')return'Exterior Lighting Operation';if(c==='Final Checks')return'Final Checks';if(c==='Paint and Body')return'Paint and Body';if(/Headlight|Front|Windshield|Hood|Front Bumper|Front Wiper/.test(i))return'Front Exterior';if(/Left|LF |LR |Driver Mirror|Driver Window/.test(i))return'Left Exterior';if(/Right|RF |RR |Passenger Mirror|Passenger Window/.test(i))return'Right Exterior';if(/Rear|Back Glass|Tail|Trunk|Liftgate|Spare Tire|Rear Wiper/.test(i))return'Rear Exterior';if(/Glass|Window|Mirror|Wiper/.test(i))return'Front Exterior';return c}
function safetyCustomerCat(r){const i=r.item,c=r.cat;if(/Brake Pad/.test(i))return'Brakes';if(/Tire Condition|Tread Depth|Rim|Inner Fender Liner/.test(i))return'Tires';if(i==='Fuel Cap Condition')return'Final Checks';if(c==='Exterior Lighting Operation')return'Lights';if(/Glass|Window|Windshield|Mirror/.test(i))return'Glass';if(/Wiper/.test(i))return'Wipers';if(/Fuel Cap/.test(i))return'Final Checks';return'Exterior Check'}
function wheelBrakeCustomerCat(r){const i=r.item;if(/LF /.test(i))return'Left Front';if(/RF /.test(i))return'Right Front';if(/LR /.test(i))return'Left Rear';if(/RR /.test(i))return'Right Rear';return'Road Test & Overall'}
function engineCustomerCat(r){const i=r.item,c=r.cat;if(c==='Cooling System'||/Coolant|Radiator|Hoses|Water Pump|Thermostat|Pressure Test/.test(i))return'Cooling System';if(/Engine Oil/.test(i))return'Engine Oil';if(/Brake Fluid|Brake Fluid Lines/.test(i))return'Brake Fluid';if(/Power Steering/.test(i))return'Power Steering Fluid';if(/Washer Fluid/.test(i))return'Washer Fluid';if(/Air Filter|Intake/.test(i))return'Intake System';if(c==='Engine Operation'||/Cold Start|Idle|Engine Noise|Exhaust Smoke|Timing Chain/.test(i))return'Engine Operation';if(/Belts|Belt Slack/.test(i))return'Belts';return'Engine Bay Condition'}
function quickUnderbodyCat(r){const i=r.item;if(/Engine Mount/.test(i))return'Engine Mounts';if(/Steering|Tie Rod/.test(i))return'Steering';if(/Control Arm|Ball Joint|Shock|Spring|Sway Bar|Subframe|Cradle/.test(i))return'Suspension';if(/Transmission|Axle|Differential|Driveshaft|Fuel Tank|Fuel Line/.test(i))return'Driveline';return'Body'}
function customerCatIndex(title,cat){const order={Safety:['Glass','Lights','Wipers','Exterior Check','Tires','Brakes','Final Checks'],Exterior:['Front Exterior','Right Exterior','Left Exterior','Rear Exterior','Paint and Body','Exterior Lighting Operation','Final Checks'],Interior:['Driver Seat Position','Passenger Seat Position','Rear Seat Position','Trunk / Cargo Area','Interior Quick Check','Interior Final Checks'],Engine:['Engine Bay Condition','Engine Operation','Engine Oil','Brake Fluid','Power Steering Fluid','Washer Fluid','Belts','Intake System','Cooling System'],Underbody:['Steering','Suspension','Driveline','Body','Engine Mounts'],'Wheels & Brakes':['Left Front','Right Front','Left Rear','Right Rear','Road Test & Overall'],'Road Test':['Powertrain & Drivability','Brake Evaluation','Steering / Ride / Handling','Feature & 4WD Checks','Parking Lot Evaluation','Post Road Test Evaluation','Road Test Annotation'],'Required Maintenance':['General Results','Safety','Engine','Driveline','Battery','Filters','Wiper Blades']};const list=order[title]||[];const i=list.indexOf(cat);return i<0?99:i}
function customerCounts(records){return{total:records.length,green:records.filter(r=>r.level==='green').length,yellow:records.filter(r=>r.level==='yellow').length,red:records.filter(r=>r.level==='red').length,neutral:records.filter(r=>r.level==='neutral').length,photos:records.reduce((n,r)=>n+r.files.length,0)}}
const customerWorst=records=>{const filled=records.filter(r=>r.level!=='neutral');if(!filled.length)return'neutral';if(filled[0]?.inspectionType==='ppi')return filled.some(r=>r.level==='red')?'red':filled.some(r=>r.level==='yellow')?'yellow':'green';if(filled.some(r=>r.level==='red'&&serviceSafetyConcern(r,r.value)&&!/Tie Rod|Ball Joint|Control Arm|Shock|Sway Bar|Suspension|Subframe|Cradle|Mount/.test((r.item||'')+' '+(r.cat||''))))return'red';return filled.some(r=>['red','yellow'].includes(r.level))?'yellow':'green'};
function customerTitle(title){return String(title).replace(/^Section \d+\s*-\s*/,'')}
function compactSectionTitle(title){return customerTitle(title).replace('Maintenance Opportunities','Maintenance').replace('Electrical, Battery & Charging','Electrical').replace('Exterior Condition','Exterior').replace('Interior Condition','Interior').replace('Under Bonnet','Engine').replace('Underbody Inspection','Underbody').replace('Vehicle History','Background').replace('Vehicle Scan','Scan')}
function customerResultText(level){return level==='red'?'Needs Attention':level==='yellow'?'Monitor':level==='green'?'Looks Good':'Not Recorded'}
function customerTone(level){return level==='red'?'border-red-400/50 bg-red-600/15 text-red-50':level==='yellow'?'border-yellow-300/50 bg-yellow-400/15 text-yellow-50':level==='green'?'border-green-400/40 bg-green-600/15 text-green-50':'border-white/10 bg-white/5 text-neutral-200'}
function exteriorZoneTone(level){return level==='red'?'border-red-200 bg-red-700/90 text-white':level==='yellow'?'border-yellow-100 bg-yellow-400/90 text-black':level==='green'?'border-green-100 bg-green-700/90 text-white':'border-orange-100 bg-black/75 text-white'}
function StatusGlyph({level}){return <span aria-hidden="true">{level==='red'?'!':level==='yellow'?'◉':level==='green'?'✓':'-'}</span>}
function customerPlainSummary(records){const red=records.filter(r=>r.level==='red').length,yellow=records.filter(r=>r.level==='yellow').length,green=records.filter(r=>r.level==='green').length;if(red)return`${red} item${red===1?'':'s'} should be reviewed for service or repair.`;if(yellow)return`${yellow} item${yellow===1?'':'s'} should be monitored or rechecked.`;if(green)return'No customer-facing concerns were recorded in this area.';return'This area has not been filled out yet.'}
function miniReportHeadline(title,level){const name=customerTitle(title);if(title==='Required Maintenance')return level==='red'?`${name}: items due`:level==='yellow'?`${name}: plan ahead`:`${name}: no immediate items recorded`;if(level==='red')return`${name}: review recommended`;if(level==='yellow')return`${name}: monitor items noted`;if(level==='green')return`${name}: no major concerns recorded`;return`${name}: not fully recorded yet`}
function miniReportCopy(title,attention,good){const name=customerTitle(title).toLowerCase();if(title==='Required Maintenance')return attention?`${attention} maintenance item${attention===1?'':'s'} should be reviewed based on the inspection entries and mileage notes below.`:good?'The completed maintenance entries did not show an immediate required item. Details remain available below.':'Required maintenance items will appear here once the inspection entries are completed.';if(attention)return`This part of the report has ${attention} result${attention===1?'':'s'} worth looking at more closely. The remaining checked items are organized below.`;if(good)return`The ${name} entries that were completed did not record a customer-facing concern. You can still open the details to see each individual result.`;return`The ${name} section is ready for entries. Once completed, the customer will see a plain-language summary here.`}
function vehicleName(record={}){return record['Vehicle Year / Make / Model']||record.VIN||'vehicle'}
function actionLabel(type='ppi'){return type==='ppi'?'Recommended Action':'Inspection Recommendation'}
function riskLabel(type='ppi'){return type==='ppi'?'Estimated Risk Level':'Overall Condition Level'}
function displayAction(v,type='ppi'){if(type==='ppi')return v;return {'Buy With Confidence':'No Immediate Action','Negotiate Price':'Service Planning Recommended','Avoid Purchase':'Service Attention Recommended'}[v]||v}
function actionCopy(v,type='ppi'){if(type!=='ppi')return {'Buy With Confidence':'Inspection results do not show an immediate service concern from the recorded items.','Negotiate Price':'Some items should be monitored, planned, or reviewed during upcoming service.','Avoid Purchase':'Recorded items indicate service or repair attention is recommended.'}[v]||'Final recommendation has not been selected yet.';return {'Buy With Confidence':'Inspection results support moving forward, while still reviewing normal ownership items.','Negotiate Price':'Use the noted items to discuss price, repairs, or seller concessions.','Avoid Purchase':'Results indicate concerns that may outweigh the value of this vehicle.'}[v]||'Final recommendation has not been selected yet.'}
function riskCopy(v,type='ppi'){if(type!=='ppi')return {Low:'Low concern based on the recorded inspection results.',Medium:'Some items should be monitored, serviced, or rechecked.',High:'Significant concerns were recorded and should be addressed carefully.'}[v]||'Condition level has not been selected yet.';return {Low:'Low concern based on the recorded inspection results.',Medium:'Some items should be reviewed before making a final purchase decision.',High:'Significant concerns were recorded and should be reviewed carefully.'}[v]||'Risk level has not been selected yet.'}
function Dot({level}){return <span className={`h-3 w-3 rounded-full ${level==='red'?'bg-red-600':level==='yellow'?'bg-yellow-400':'bg-green-500'}`}/>}
function PhotoWarn({rowKey,item,value,hasPhoto}){if(!photoReq(item,value))return null;return <button type="button" onClick={()=>document.getElementById(photoId(rowKey))?.click()} className={`no-print w-full text-left text-xs ${hasPhoto?'text-green-300 bg-green-500/10 border-green-300/30':'text-red-200 bg-red-600/10 border-red-400/40'} border rounded-xl px-3 py-2`}>{photoLabel(item)} {hasPhoto?'attached.':'before completion. Click to upload.'}</button>}
function Warn({children,red=false}){return <p className={`no-print text-xs ${red?'text-red-200 bg-red-600/10 border-red-400/40':'text-yellow-300 bg-yellow-500/10 border-yellow-300/30'} border rounded-xl px-3 py-2`}>{children}</p>}
function Info({label,value,level='neutral'}){return <div className={`rounded-2xl border p-4 ${level==='neutral'?'border-orange-300/20 bg-neutral-950':tone(level)}`}><p className="text-xs uppercase tracking-[0.18em] opacity-80">{label}</p><p className="mt-2 whitespace-pre-line leading-relaxed">{value}</p></div>}
const Field=({label,children})=><div className="mb-3"><label className="text-sm text-neutral-400 block mb-2">{label}</label>{children}</div>;
const TextArea=({label,value})=><Field label={label}><textarea rows={6} {...(value!==undefined?{value,readOnly:true}:{defaultValue:''})} className={inp+' resize-none'}/></Field>;
const Card=({children,className='',...props})=><div {...props} className={`min-w-0 max-w-full bg-black/90 border border-white/10 rounded-3xl p-4 sm:p-6 ${className}`}>{children}</div>;
const Cell=({label,children})=><div className="md:p-4"><p className="md:hidden text-xs uppercase tracking-[0.18em] text-neutral-500 mb-2">{label}</p>{children}</div>;
const Btn=({children,...p})=><button {...p} className="no-print rounded-2xl border border-orange-300/20 px-5 py-3 hover:bg-orange-500/20">{children}</button>;
function Disclaimer(){return <Card><p className="text-neutral-300 text-sm leading-relaxed"><b className="block text-neutral-400 uppercase tracking-[0.2em] mb-2">Inspection Disclaimer</b>This report is a visual vehicle inspection based on the vehicle condition at the time inspected. It is not a diagnosis, warranty, guarantee, teardown inspection, or prediction of future failures. Items hidden by covers, access limits, weather, road conditions, or required disassembly may not be verified.</p></Card>}
function key(s,c,i){return`${s}|${c}|${i}`}
function id(k){let h=0;for(const c of String(k))h=(h*31+c.charCodeAt(0))|0;return'r'+Math.abs(h)}
function sectionId(s){return's'+s.replace(/[^a-z0-9]+/gi,'-').toLowerCase()}
function catId(s,c){return'cat-'+sectionId(s)+'-'+sectionId(c)}
function photoId(k){return'photo-'+String(k).replace(/[^a-z0-9]+/gi,'-').toLowerCase()}
function del(o,k){const n={...o};delete n[k];return n}
const CSS='html,body,#root{max-width:100%;overflow-x:hidden}.print-only{display:none}@media print{@page{size:landscape;margin:.35in}.no-print,.print-hide,.screen-only{display:none!important}.print-only{display:block!important}*{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}html,body{background:white!important;color:#111!important;height:auto!important;max-height:none!important;overflow:visible!important}#root,main,main>div,#customer-preview,#customer-preview>div,.print-only,.print-report{height:auto!important;max-height:none!important;overflow:visible!important}main{background:white!important;padding:0!important}.print-report{display:block!important;color:#111!important;font-family:Inter,Arial,sans-serif;width:100%!important}.print-cover{border:2px solid #f28c0f;border-radius:18px;padding:18px;margin-bottom:18px}.print-eyebrow{margin:0 0 6px;color:#b45309;font-size:10px;text-transform:uppercase;letter-spacing:.16em}.print-cover h1{margin:0 0 12px;font-size:28px;line-height:1.1}.print-detail-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:8px}.print-detail{border:1px solid #ddd;border-radius:10px;padding:8px;background:#fff7ed}.print-detail span{display:block;color:#666;font-size:10px;text-transform:uppercase;letter-spacing:.12em}.print-detail b{display:block;margin-top:3px;font-size:12px}.print-section{break-inside:auto;page-break-inside:auto;margin:0 0 18px;overflow:visible!important;height:auto!important;max-height:none!important}.print-section h2{border-bottom:3px solid #f28c0f;margin:0 0 10px;padding-bottom:5px;font-size:20px}.print-group{break-inside:auto;page-break-inside:auto;margin:0 0 12px;overflow:visible!important;height:auto!important;max-height:none!important}.print-group h3{margin:0 0 6px;font-size:14px;color:#111}.print-row{break-inside:auto;page-break-inside:auto;display:block;border:1px solid #ddd;border-left:7px solid #9ca3af;border-radius:10px;padding:8px 10px;margin-bottom:6px;background:#fff;overflow:visible!important}.print-row b{font-size:12px}.print-row p{margin:3px 0 0;font-size:11px;line-height:1.35;color:#333;white-space:pre-line}.print-row span{display:inline-block;margin-top:5px;border:1px solid #ddd;border-radius:999px;padding:3px 8px;font-size:10px;font-weight:800}.print-row-has-photos{break-inside:avoid-page;page-break-inside:avoid}.print-photos{display:block;margin-top:4px;overflow:visible!important}.print-photos figure{position:relative;display:block;height:4.55in;margin:6px 0 0;padding:0;break-inside:avoid-page;page-break-inside:avoid;overflow:hidden;background:transparent}.print-photos figure+figure{break-before:page;page-break-before:always}.print-photos img{position:absolute;left:50%;top:50%;display:block;width:4.55in;height:7.6in;max-height:none;object-fit:contain;border-radius:4px;background:transparent;transform:translate(-50%,-50%) rotate(90deg)}.print-video-placeholder{display:grid;place-items:center;min-height:1.4in;border:2px dashed #f28c0f;border-radius:12px;padding:14px;text-align:center;background:#fff7ed;color:#111}.print-video-placeholder p{font-size:12px!important}.print-video-placeholder small{font-size:10px;color:#555}.print-photos figcaption{display:none}.print-row-green{border-left-color:#16a34a}.print-row-yellow{border-left-color:#f59e0b}.print-row-red{border-left-color:#dc2626}}';
